let T=JSON.parse(JSON.stringify(PRESETS[0]));
let activePresetIdx=null;
// THEME_ORIGIN: snapshot of the theme at time of load/switch
// All per-swatch, per-group and global resets restore to this.
let THEME_ORIGIN=JSON.parse(JSON.stringify(DEFAULTS));
function snapshotOrigin(){THEME_ORIGIN=JSON.parse(JSON.stringify(T));clearUndoStack();pushUndo();checkDirty();updateDeleteBtn();}

/* ══════════════════════════════════════════════════════════
   UNDO / REDO STACK
   Records committed T snapshots. Stack resets on theme load.
   Dirty detection: compare current T against THEME_ORIGIN.
══════════════════════════════════════════════════════════ */
let undoStack=[];    // array of JSON snapshots, oldest first
let undoPtr=-1;      // current position in stack
const MAX_UNDO=50;

function pushUndo(){
  const snap=JSON.stringify(T);
  // Drop any redo states ahead of current pointer
  undoStack=undoStack.slice(0,undoPtr+1);
  // Don't push if identical to current
  if(undoStack.length&&undoStack[undoStack.length-1]===snap)return;
  undoStack.push(snap);
  if(undoStack.length>MAX_UNDO)undoStack.shift();
  undoPtr=undoStack.length-1;
  refreshUndoRedo();
  checkDirty();
}

function undoAction(){
  if(undoPtr<=0)return;
  undoPtr--;
  T=JSON.parse(undoStack[undoPtr]);
  buildAll();applyTheme();requestAnimationFrame(fit);
  refreshUndoRedo();checkDirty();
}

function redoAction(){
  if(undoPtr>=undoStack.length-1)return;
  undoPtr++;
  T=JSON.parse(undoStack[undoPtr]);
  buildAll();applyTheme();requestAnimationFrame(fit);
  refreshUndoRedo();checkDirty();
}

function clearUndoStack(){
  undoStack=[];undoPtr=-1;
  refreshUndoRedo();
}

function refreshUndoRedo(){
  const u=document.getElementById('undoBtn');
  const r=document.getElementById('redoBtn');
  if(u){if(undoPtr<=0)u.setAttribute('disabled','');else u.removeAttribute('disabled');}
  if(r){if(undoPtr>=undoStack.length-1)r.setAttribute('disabled','');else r.removeAttribute('disabled');}
}

/* ── Dirty detection ── */
function isDirty(){return JSON.stringify(T)!==JSON.stringify(THEME_ORIGIN);}

/* ── Update Save button state ── */
function checkDirty(){
  const dirty=isDirty();
  const saveBtn=document.getElementById('saveBtn');
  const saveLabel=document.getElementById('saveBtnLabel');
  const isPreset=!!PRESETS.find(p=>p.label===T.label);
  if(saveBtn){
    if(dirty){saveBtn.removeAttribute('disabled');}else{saveBtn.setAttribute('disabled','');}
    if(saveLabel)saveLabel.textContent=isPreset?'Save as new':'Save';
  }
}

/* ── Delete button: enabled only when current theme exists in Library ── */
function updateDeleteBtn(){
  const btn=document.getElementById('deleteThemeBtn');
  if(!btn)return;
  const lib=libLoad();
  const inLib=lib.some(x=>x.label===T.label);
  if(inLib)btn.removeAttribute('disabled');
  else btn.setAttribute('disabled','');
}

/* ── Wire Save button ── */
document.getElementById('saveBtn').addEventListener('click',()=>{
  const lib=libLoad();
  const inLib=lib.some(x=>x.label===T.label);
  if(inLib){
    // User theme — silent update in place
    const idx=lib.findIndex(x=>x.label===T.label);
    const entry={...JSON.parse(JSON.stringify(T)),savedAt:Date.now()};
    if(idx>=0)lib[idx]=entry;else lib.unshift(entry);
    libSave(lib);
    snapshotOrigin();checkDirty();updateDeleteBtn();
    showToast(`"${T.label}" saved`);
  } else {
    // Preset — prompt for new name
    showPrompt('Name for this theme:',T.label+' (custom)',name=>{
      T.label=name;
      const lib2=libLoad();
      lib2.unshift({...JSON.parse(JSON.stringify(T)),savedAt:Date.now()});
      libSave(lib2);
      snapshotOrigin();checkDirty();updateDeleteBtn();
      const nameLbl=document.getElementById('ftbThemeName');
      if(nameLbl)nameLbl.textContent=name;
      showToast(`"${name}" saved to Library`);
    });
  }
});

/* ── Wire Delete button ── */
document.getElementById('deleteThemeBtn').addEventListener('click',()=>{
  const lib=libLoad();
  const idx=lib.findIndex(x=>x.label===T.label);
  if(idx<0)return; // not in library, do nothing
  showConfirm(`Delete "${T.label}"? This cannot be undone.`,()=>{
    lib.splice(idx,1);
    libSave(lib);
    T=JSON.parse(JSON.stringify(DEFAULTS));
    snapshotOrigin();
    clearUndoStack();
    buildAll();
    applyTheme();
    requestAnimationFrame(()=>requestAnimationFrame(fit));
    const nameLbl=document.getElementById('ftbThemeName');
    if(nameLbl)nameLbl.textContent='Default Fabric';
    updateDeleteBtn();
    showToast('Theme deleted');
  });
});

/* ── Wire Undo/Redo buttons + keyboard shortcuts ── */
document.getElementById('undoBtn').addEventListener('click',undoAction);
document.getElementById('redoBtn').addEventListener('click',redoAction);

/* Extend keyboard shortcut handler to include undo/redo */


function updatePanelFoot(){
  const lbl=document.getElementById('pfLabel'),dot=document.getElementById('pfDot');
  if(lbl)lbl.textContent=T.label||'Custom theme';
  if(dot&&T.theme&&T.theme.colors&&T.theme.colors.primaryColors)dot.style.background=T.theme.colors.primaryColors[0];
}
function applyTheme(){
  const c=T.theme.colors,p=T.theme.page,e=T.theme.elements,ty=T.theme.typography;
  c.primaryColors.forEach((v,i)=>{root.style.setProperty('--p'+(i+1),v);root.style.setProperty('--p'+(i+1)+'-text',tc(v));});
  root.style.setProperty('--p1-text',tc(c.primaryColors[0]));
  const sc=c.structuralColors;
  root.style.setProperty('--out1',sc.outline1);root.style.setProperty('--out2',sc.outline2);
  root.style.setProperty('--struct-bg',sc.background);root.style.setProperty('--struct-icon',sc.icon);
  root.style.setProperty('--struct-accent',sc.accent);root.style.setProperty('--struct-subtle',sc.subtleFill);
  root.style.setProperty('--pos',c.semantic.positive);root.style.setProperty('--neg',c.semantic.negative);root.style.setProperty('--neu',c.semantic.neutral);
  root.style.setProperty('--canvas-bg',p.canvas.background.color);
  root.style.setProperty('--canvas-border-color',p.canvas.border.color);
  root.style.setProperty('--canvas-border-w',p.canvas.border.isEnabled?p.canvas.border.width+'px':'0px');
  const cr=p.canvas.cornerRadius;root.style.setProperty('--canvas-radius',cr.isEnabled?cr.radiusTopLeft+'px':'0px');
  const cs=p.canvas.shadow;root.style.setProperty('--canvas-shadow',cs.isEnabled?`0 ${cs.distance}px ${cs.blur}px ${cs.color}`:'none');
  root.style.setProperty('--wallpaper',p.wallpaper.color);
  root.style.setProperty('--el-bg',e.background.color);
  root.style.setProperty('--el-border-color',e.border.color);
  root.style.setProperty('--el-border-w',e.border.isEnabled?e.border.width+'px':'0px');
  const er=e.cornerRadius;root.style.setProperty('--el-radius',er.isEnabled?er.radiusTopLeft+'px':'0px');
  const es=e.shadow;root.style.setProperty('--el-shadow',es.isEnabled?`0 ${es.distance}px ${es.blur}px ${es.color}`:'none');
  if(e.padding.isEnabled){root.style.setProperty('--el-pad-t',e.padding.topPadding+'px');root.style.setProperty('--el-pad-r',e.padding.rightPadding+'px');root.style.setProperty('--el-pad-b',e.padding.bottomPadding+'px');root.style.setProperty('--el-pad-l',e.padding.leftPadding+'px');}
  root.style.setProperty('--header-bg',e.header.backgroundColor);root.style.setProperty('--header-border',e.header.borderColor);root.style.setProperty('--header-icon',e.header.iconColor);
  root.style.setProperty('--tip-bg',e.tooltip.backgroundColor);root.style.setProperty('--tip-color',e.tooltip.color);
  root.style.setProperty('--text-color',ty.color);root.style.setProperty('--font-family',ty.fontFamily);root.style.setProperty('--font-size',ty.fontSize+'px');
  updateThemeIcon();
  if(window._wcagRefresh)_wcagRefresh();
}

/* ── Theme-switcher icon: recolour the 2x2 swatch grid to the
   current theme's own primary colours (P1-P4), so the icon itself
   previews the active theme and changes live with every switch. ── */
function updateThemeIcon(){
  const p=(T.theme&&T.theme.colors&&T.theme.colors.primaryColors)||[];
  const c1=p[0]||'#117865',c2=p[1]||c1,c3=p[2]||c1,c4=p[3]||c2;
  const f1=document.getElementById('ftbThemeIconFill1');
  const f2=document.getElementById('ftbThemeIconFill2');
  const f3=document.getElementById('ftbThemeIconFill3');
  const f4=document.getElementById('ftbThemeIconFill4');
  if(f1)f1.style.color=c1;
  if(f2)f2.style.color=c2;
  if(f3)f3.style.color=c3;
  if(f4)f4.style.color=c4;
}

/* ── Tooltip ──
   Contrast is checked against the CURRENT theme's own canvas
   background (not a hardcoded white), so a dark theme's swatches get
   judged against its actual dark backdrop instead of always failing
   against white regardless of what the theme really looks like. */
const tipEl=$('#tip');let _tipTarget=null,_tipHex=null;
function currentCanvasBg(){
  try{return(T&&T.theme&&T.theme.page&&T.theme.page.canvas&&T.theme.page.canvas.background&&T.theme.page.canvas.background.color)||'#FFFFFF';}
  catch(e){return'#FFFFFF';}
}
function tipHTML(hex,bg){
  bg=bg||currentCanvasBg();
  const r=cr2(hex,bg);
  const line=(lbl,t)=>{const ok=r>=t;return `<div class="chk"><span class="m ${ok?'pass':'fail'}">${ok?'✓':'✕'}</span><span>${lbl}</span></div>`;};
  const st=r>=4.5?['AA','#107c10']:r>=3?['AA large','#8a6d00']:['Fail','#c50f1f'];
  return `<div class="th"><span class="sw" style="background:${hex}"></span><span class="hx">${hex}</span><span class="st" style="background:color-mix(in srgb,${st[1]} 15%,#fff);color:${st[1]}">${st[0]}</span></div>
    <div class="ratio">Contrast vs canvas: <b>${r.toFixed(2)}:1</b></div>
    ${line('Normal text — 4.5:1',4.5)}${line('Large / UI — 3:1',3)}${line('AAA — 7:1',7)}
    <div class="cmp"><span class="sw" style="background:${bg}"></span>Compared vs ${bg.toUpperCase()}</div>`;}
function attachTip(el,getHex,getBg){
  el.addEventListener('mouseenter',()=>{_tipTarget=el;_tipHex=getHex;tipEl.innerHTML=tipHTML(getHex(),getBg?getBg():currentCanvasBg());tipEl.classList.add('show');plTip(el);});
  el.addEventListener('mousemove',()=>plTip(el));
  el.addEventListener('mouseleave',()=>{tipEl.classList.remove('show');_tipTarget=null;});}
function plTip(el){const r=el.getBoundingClientRect(),tw=tipEl.offsetWidth,th=tipEl.offsetHeight;let x=r.left+r.width/2-tw/2,y=r.top-th-8;if(y<8)y=r.bottom+8;x=Math.max(8,Math.min(x,innerWidth-tw-8));tipEl.style.left=x+'px';tipEl.style.top=y+'px';}

/* ── Chart tooltip system ── */
const cTip=document.getElementById('chartTip');
function showChartTip(evt,title,rows){
  // rows: [{color, label, value}]
  let html='';
  if(title)html+=`<div class="chart-tip-title">${title}</div>`;
  rows.forEach(r=>{
    if(r.color){
      html+=`<div class="chart-tip-row"><span class="chart-tip-dot" style="background:${r.color}"></span><span>${r.label}: <b>${r.value}</b></span></div>`;
    } else {
      html+=`<div class="chart-tip-row"><span>${r.label}: <b>${r.value}</b></span></div>`;
    }
  });
  cTip.innerHTML=html;
  cTip.classList.add('show');
  posChartTip(evt);
}
function posChartTip(evt){
  const tw=cTip.offsetWidth,th=cTip.offsetHeight;
  let x=evt.clientX+14,y=evt.clientY-th/2;
  if(x+tw>innerWidth-8)x=evt.clientX-tw-14;
  y=Math.max(8,Math.min(y,innerHeight-th-8));
  cTip.style.left=x+'px';cTip.style.top=y+'px';
}
function hideChartTip(){cTip.classList.remove('show');}
function addChartTip(el,title,rows){
  el.style.cursor='pointer';
  el.addEventListener('mouseenter',e=>showChartTip(e,title,rows));
  el.addEventListener('mousemove',e=>posChartTip(e));
  el.addEventListener('mouseleave',hideChartTip);
}

/* ── Color accordion groups ── */
function buildColorGroup(host,name,items,renderFn,open){
  const sec=document.createElement('section');sec.className='cgroup'+(open?' open':'');
  const prev=items.slice(0,10).map(it=>Array.isArray(it)?it[2]:it);
  sec.innerHTML=`<div class="cghead" role="button" tabindex="0">
    <span class="chev">${IC.chevRight}</span>
    <span class="cg-name">${name}</span>
    <span class="cg-count">${items.length}</span>
    <span class="cg-prev">${prev.map(c=>`<span style="background:${c}"></span>`).join('')}</span>
    <button class="cg-reset f-btn-subtle" title="Reset ${name}">${IC.reset}</button>
  </div><div class="cgbody"></div>`;
  const head=sec.querySelector('.cghead'),body=sec.querySelector('.cgbody'),resetBtn=sec.querySelector('.cg-reset');
  head.addEventListener('click',e=>{if(e.target.closest('.cg-reset'))return;sec.classList.toggle('open');});
  head.addEventListener('keydown',e=>{if((e.key==='Enter'||e.key===' ')&&!e.target.closest('.cg-reset')){e.preventDefault();sec.classList.toggle('open');}});
  const resets=[];
  renderFn(body,resets);
  resetBtn.addEventListener('click',e=>{e.stopPropagation();resets.forEach(fn=>fn());});
  host.appendChild(sec);
  return{updatePreview(){const dots=sec.querySelectorAll('.cg-prev span');prev.forEach((_,i)=>{if(dots[i])dots[i].style.background=items[i]?Array.isArray(items[i])?items[i][2]:items[i]:prev[i];});}};
}
/* ── Drag-to-reorder for primary-colour cards — same whole-card
   press-and-drag interaction as the New Theme wizard's palette
   preview (no gripper icon; a plain click still opens the colour
   picker underneath). Operates directly on T.theme.colors and
   THEME_ORIGIN (moved in lockstep so each card's "reset to original"
   value keeps following that same card), then reuses the normal
   applyTheme()/pushUndo()/buildColors() flow like any other edit. ── */
let sideDragSourceEl=null;
function sideLiveReorderSwatch(dragEl,targetEl){
  if(!dragEl||!targetEl||dragEl===targetEl)return;
  const row=dragEl.parentElement;
  if(!row||targetEl.parentElement!==row)return;
  const items=[...row.querySelectorAll('.swblock-reorderable')];
  const firstRects=new Map(items.map(el=>[el,el.getBoundingClientRect()]));
  const dragRect=dragEl.getBoundingClientRect();
  const targetRect=targetEl.getBoundingClientRect();
  // Grid is 2 columns: prefer comparing rows first, fall back to
  // horizontal position when drag/target share a row.
  const sameRow=Math.abs(dragRect.top-targetRect.top)<=4;
  const goesBefore=sameRow?dragRect.left<targetRect.left:dragRect.top<targetRect.top;
  row.insertBefore(dragEl,goesBefore?targetEl.nextSibling:targetEl);
  items.forEach(el=>{
    const beforeRect=firstRects.get(el);
    const afterRect=el.getBoundingClientRect();
    const dx=beforeRect.left-afterRect.left,dy=beforeRect.top-afterRect.top;
    if(dx||dy){
      el.style.transition='none';
      el.style.transform=`translate(${dx}px,${dy}px)`;
      requestAnimationFrame(()=>{el.style.transition='transform 160ms ease';el.style.transform='';});
    }
  });
}
function sideCommitDragReorder(dragEl){
  if(!dragEl)return;
  dragEl.classList.remove('dragging');
  const row=dragEl.parentElement;
  if(!row)return;
  row.classList.remove('swcards-dragging');
  const finalItems=[...row.querySelectorAll('.swblock-reorderable')];
  const toIdx=finalItems.indexOf(dragEl);
  const fromIdx=parseInt(dragEl.dataset.reorderIndex,10);
  if(isNaN(fromIdx)||isNaN(toIdx)||fromIdx===toIdx)return;
  const arr=T.theme.colors.primaryColors;
  if(fromIdx<0||fromIdx>=arr.length||toIdx<0||toIdx>=arr.length)return;
  const[movedVal]=arr.splice(fromIdx,1);
  arr.splice(toIdx,0,movedVal);
  // Deliberately do NOT reorder THEME_ORIGIN's array to match — it must
  // stay a pristine, untouched snapshot of the theme as originally
  // loaded (that's what isDirty()/pushUndo() diff against to decide
  // whether Save/Save-as-copy should appear, and what per-slot reset
  // buttons restore to). Moving it in lockstep with T made every
  // reorder invisible to the dirty-check, since T and THEME_ORIGIN
  // would end up shuffled identically and compare as unchanged. Each
  // "Color N" slot's reset button now resets to whatever was
  // originally in position N — consistent with how every other edit
  // (recolouring a swatch) already behaves.
  applyTheme();
  pushUndo();
  buildColors();
}
const SIDE_SWATCH_DRAG_THRESHOLD=6;
function attachSideSwatchDrag(el){
  let startX=0,startY=0,dragging=false,suppressClick=false;
  function onMove(e){
    if(!dragging){
      if(Math.hypot(e.clientX-startX,e.clientY-startY)<SIDE_SWATCH_DRAG_THRESHOLD)return;
      dragging=true;suppressClick=true;
      sideDragSourceEl=el;
      el.classList.add('dragging');
      if(el.parentElement)el.parentElement.classList.add('swcards-dragging');
    }
    e.preventDefault();
    const target=document.elementFromPoint(e.clientX,e.clientY);
    const over=target&&target.closest('.swblock-reorderable');
    if(over&&sideDragSourceEl&&over!==sideDragSourceEl)sideLiveReorderSwatch(sideDragSourceEl,over);
  }
  function onUp(){
    document.removeEventListener('pointermove',onMove);
    document.removeEventListener('pointerup',onUp);
    document.removeEventListener('pointercancel',onCancel);
    if(dragging){sideCommitDragReorder(el);sideDragSourceEl=null;dragging=false;}
  }
  function onCancel(){
    document.removeEventListener('pointermove',onMove);
    document.removeEventListener('pointerup',onUp);
    document.removeEventListener('pointercancel',onCancel);
    el.classList.remove('dragging');
    if(el.parentElement)el.parentElement.classList.remove('swcards-dragging');
    sideDragSourceEl=null;dragging=false;
  }
  el.addEventListener('pointerdown',e=>{
    if(e.button!==undefined&&e.button!==0)return;
    startX=e.clientX;startY=e.clientY;dragging=false;suppressClick=false;
    document.addEventListener('pointermove',onMove);
    document.addEventListener('pointerup',onUp);
    document.addEventListener('pointercancel',onCancel);
  });
  el.addEventListener('click',e=>{
    if(suppressClick){e.preventDefault();e.stopPropagation();suppressClick=false;}
  },true);
}

function mkSwblock(parent,label,def,getCurrent,setter,opts={}){
  const el=document.createElement('div');el.className='swblock';
  const cur=getCurrent();
  el.innerHTML=`<input type="color" value="${cur}"><div class="info"><span class="lbl">${label}</span><span class="hx">${cur}</span></div><span class="cd"></span><span class="rst" title="Reset">${IC.reset}</span>`;
  const inp=el.querySelector('input'),hx=el.querySelector('.hx'),info=el.querySelector('.info'),cd=el.querySelector('.cd'),rst=el.querySelector('.rst');
  function paint(v){el.style.background=v;const t=tc(v);info.style.color=t;rst.style.color=t;hx.textContent=v.toUpperCase();const r=cr2(v,currentCanvasBg());cd.className='cd';cd.style.background=r>=4.5?'#3fbf3f':r>=3?'#f5a623':'#c8c6c4';}
  function apply(v){const n=norm(v);if(!n)return;setter(n);inp.value=n;applyTheme();paint(n);}
  inp.addEventListener('input',()=>apply(inp.value));
  inp.addEventListener('change',()=>pushUndo());
  rst.addEventListener('click',e=>{e.stopPropagation();apply(def);pushUndo();});
  attachTip(el,()=>inp.value);
  if(opts.reorderIndex!==undefined){
    el.classList.add('swblock-reorderable');
    el.dataset.reorderIndex=String(opts.reorderIndex);
    attachSideSwatchDrag(el);
  }
  paint(cur);parent.appendChild(el);
  return{reset:()=>apply(def),refresh(){inp.value=getCurrent();paint(inp.value);}};
}

let refreshers=[];

function buildColors(){
  const host=$('#tp-colors');
  // Rebuilding wipes and recreates every accordion section from
  // scratch, which used to always re-collapse them (hardcoded
  // `false`) regardless of what the user had open — most noticeable
  // right after a drag-to-reorder, since that also calls buildColors().
  // Remember which sections were open beforehand and restore that.
  const openNames=new Set([...host.querySelectorAll('.cgroup.open .cg-name')].map(el=>el.textContent));
  // Also, if a swatch's accessibility tooltip happened to be showing
  // (mouse still "over" a swatch that's about to be deleted), force it
  // closed first — innerHTML='' below removes the element without
  // ever firing a real mouseleave, so the shared tooltip would
  // otherwise stay stuck on screen with nothing left to dismiss it.
  if(typeof tipEl!=='undefined'){tipEl.classList.remove('show');_tipTarget=null;}
  host.innerHTML='';refreshers=refreshers.filter(r=>r.tab!=='colors');
  const c=T.theme.colors;

  buildColorGroup(host,'Primary Colors',c.primaryColors,(body,resets)=>{
    const grid=document.createElement('div');grid.className='swcards';
    c.primaryColors.forEach((v,i)=>{
      const ctrl=mkSwblock(grid,'Color '+(i+1),THEME_ORIGIN.theme.colors.primaryColors[i],()=>c.primaryColors[i],v=>{c.primaryColors[i]=v;},{reorderIndex:i});
      resets.push(ctrl.reset);refreshers.push({tab:'colors',fn:ctrl.refresh});});
    body.appendChild(grid);},openNames.has('Primary Colors'));

  buildColorGroup(host,'Structural Colors',Object.values(c.structuralColors),(body,resets)=>{
    const grid=document.createElement('div');grid.className='swcards';
    [['outline1','Outline 1'],['outline2','Outline 2'],['background','Background'],['icon','Icon'],['accent','Accent'],['subtleFill','Subtle Fill']].forEach(([k,l])=>{
      const ctrl=mkSwblock(grid,l,THEME_ORIGIN.theme.colors.structuralColors[k],()=>c.structuralColors[k],v=>{c.structuralColors[k]=v;});
      resets.push(ctrl.reset);refreshers.push({tab:'colors',fn:ctrl.refresh});});
    body.appendChild(grid);},openNames.has('Structural Colors'));

  buildColorGroup(host,'Semantic Colors',Object.values(c.semantic),(body,resets)=>{
    const grid=document.createElement('div');grid.className='swcards';
    [['positive','Positive'],['negative','Negative'],['neutral','Neutral']].forEach(([k,l])=>{
      const ctrl=mkSwblock(grid,l,THEME_ORIGIN.theme.colors.semantic[k],()=>c.semantic[k],v=>{c.semantic[k]=v;});
      resets.push(ctrl.reset);refreshers.push({tab:'colors',fn:ctrl.refresh});});
    body.appendChild(grid);},openNames.has('Semantic Colors'));
}

/* ── Property helpers ── */
function mkColorRow(p,label,get,set){
  const row=document.createElement('div');row.className='prop-row';
  row.innerHTML=`<span class="prop-lbl">${label}</span><div class="prop-color"><span class="swatch"><input type="color" value="${get().slice(0,7)}"></span><input class="f-input hex" type="text" value="${get().slice(0,7).toUpperCase()}" spellcheck="false" maxlength="7"></div>`;
  const inp=row.querySelector('input[type=color]'),hex=row.querySelector('.f-input'),sw=row.querySelector('.swatch');
  function paint(){sw.style.background=inp.value;hex.value=inp.value.toUpperCase();}
  inp.addEventListener('input',()=>{set(inp.value);applyTheme();paint();});
  inp.addEventListener('change',()=>{pushUndo();});
  hex.addEventListener('change',()=>{const n=norm(hex.value);if(n){inp.value=n.slice(0,7);set(n);applyTheme();paint();pushUndo();}});
  paint();p.appendChild(row);
  return{refresh(){inp.value=get().slice(0,7);paint();}};
}
function mkNum(p,label,get,set,min,max,unit){
  const row=document.createElement('div');row.className='prop-row';
  const mn=min??0,mx=max??999;
  // SpinButton: input + up/down arrow buttons (Fabric iconography)
  const upSVG=`<svg viewBox="0 0 9 9" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"><path d="M1.5 6L4.5 3L7.5 6"/></svg>`;
  const dnSVG=`<svg viewBox="0 0 9 9" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"><path d="M1.5 3L4.5 6L7.5 3"/></svg>`;
  row.innerHTML=`<span class="prop-lbl">${label}</span><div class="f-spinbtn"><input class="f-input num" type="number" value="${get()}" min="${mn}" max="${mx}" step="1"><div class="f-spin-arrows"><button class="f-spin-arrow" tabindex="-1" title="Increase">${upSVG}</button><button class="f-spin-arrow" tabindex="-1" title="Decrease">${dnSVG}</button></div></div>${unit?`<span class="unit">${unit}`+'</span>':''}`;
  const inp=row.querySelector('input');
  const [up,dn]=row.querySelectorAll('.f-spin-arrow');
  function commit(v){const c=Math.max(mn,Math.min(mx,Math.round(Number(v)||0)));inp.value=c;set(c);applyTheme();}
  inp.addEventListener('input',()=>commit(inp.value));
  inp.addEventListener('change',()=>pushUndo());
  up.addEventListener('click',()=>{commit(Number(inp.value)+1);pushUndo();});
  dn.addEventListener('click',()=>{commit(Number(inp.value)-1);pushUndo();});
  p.appendChild(row);return{refresh(){inp.value=get();}};
}
function mkToggle(p,label,get,set){
  const row=document.createElement('div');row.className='prop-row';
  const id='tg'+Math.random().toString(36).slice(2);
  row.innerHTML=`<span class="prop-lbl">${label}</span><label class="f-toggle"><input type="checkbox" id="${id}" ${get()?'checked':''}><span class="track"></span><span class="tlbl"></span></label>`;
  const inp=row.querySelector('input');
  inp.addEventListener('change',()=>{set(inp.checked);applyTheme();pushUndo();});
  p.appendChild(row);return{refresh(){inp.checked=get();}};
}
