/* ── Planning module — matrix/grid view ──
   Reuses the exact same .matrix component and CSS variables as the
   Intelligence writeback matrix (Inforiver-based grid), so it already
   inherits every colour/typography token from the current theme with
   no new schema. Deeper hierarchy (region > country > category >
   sub-category) and year-grouped columns, per the reference screenshot. */
(function(){
  const years=['2023','2024','2025','2026'];
  const subCols=[
    {label:'Total'},
    {label:'Profit','sub':'in Thousands'},
    {label:'Sales','sub':'in Thousands'},
    {label:'Quantity','sub':'in Thousands'}
  ];
  const yearRow=document.getElementById('planningYearRow');
  const subRow=document.getElementById('planningSubRow');
  const body=document.getElementById('planningMatrixBody');
  if(!yearRow||!subRow||!body)return;

  yearRow.innerHTML='<th class="lead"></th>'+years.map(y=>`<th class="lead" colspan="${subCols.length}">${y}</th>`).join('');
  subRow.innerHTML='<th class="lead">Sub-Category</th>'+years.map(()=>subCols.map(c=>`<th>${c.label}${c.sub?`<br><span style="font-weight:400;font-size:10.5px;opacity:.7">${c.sub}</span>`:''}</th>`).join('')).join('');

  const IC={chevRight:'<svg viewBox="0 0 16 16" width="12" height="12" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M6 4l4 4-4 4"/></svg>',chevDown:'<svg viewBox="0 0 16 16" width="12" height="12" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M4 6l4 4 4-4"/></svg>'};
  const rows=[
    ['lvl0','d',0,'All'],
    ['lvl1','d',1,'North America'],
    ['lvl2','d',2,'Canada'],
    ['lvl3','d',3,'Electronics'],
    ['lvl4','',4,'Audio'],['lvl4','',4,'Comp'],['lvl4','',4,'Mobile'],
    ['lvl3','d',3,'Personal Care'],
    ['lvl4','',4,'Baby Care'],['lvl4','',4,'Hair Care'],
    ['lvl2','d',2,'Mexico'],
    ['lvl3','d',3,'Electronics'],
    ['lvl4','',4,'Audio'],['lvl4','',4,'Comp'],
    ['lvl1','d',1,'Europe'],
    ['lvl2','d',2,'Europe'],
    ['lvl3','d',3,'Electronics'],
    ['lvl4','',4,'Audio']
  ];
  const totalCols=years.length*subCols.length;
  rows.forEach((r,ri)=>{
    const[cls,chevState,level,label]=r;
    const tr=document.createElement('tr');tr.className=cls;
    const chev=chevState==='r'?`<span class="mx-chev">${IC.chevRight}</span>`:chevState==='d'?`<span class="mx-chev">${IC.chevDown}</span>`:'';
    const indentCls=level>0?` indent${Math.min(level,4)}`:'';
    let cells='';
    for(let ci=0;ci<totalCols;ci++){
      const v=(((ri*7+ci*3+11)%97)/97*3+0.05).toFixed(2);
      cells+=`<td${ci%subCols.length===0?' class="grpdiv"':''}>${v}</td>`;
    }
    tr.innerHTML=`<td class="lead${indentCls}">${chev}${label}</td>${cells}`;
    body.appendChild(tr);
  });
})();

/* ── PowerTable module — "Table layout" ──
   Structural chrome (header/stripe/gridlines) reuses the same
   structuralColors tokens as Intelligence and Planning. Per-value tag
   pills (Single/Multi Select) cycle through the 8 primaryColors via
   the --p1..--p8 / --p{n}-text vars until a dedicated ~50-colour
   category palette is added later. Star rating, checkbox, slider
   handle and button all use primaryColors[0] (--p1 / --p1-text). */
(function(){
  const headRow=document.getElementById('ptHeadRow');
  const body=document.getElementById('ptBody');
  if(!headRow||!body)return;

  const COLS=['','Task Name','Phone Number','Currency','Number Slider','Rating','Checkbox','Percent','Percent Complete','Single Select','Multi Select','Check List','Image','Button'];
  headRow.innerHTML=COLS.map(c=>`<th>${c}</th>`).join('');

  const TASKS=['Gantt Product Engineering','Requirements Gathering','Project Plan','Walkthrough & Ideation','Design Phase Kick off','Business case study','Systems architecture','Ux Brainstorm','UI Implementation','Feedbacks & Review','Dev handoff','Development Kickoff','Environment Setup','Internal Audit','Back-end Development','Front-end Development','Development Review','Quality Assurance Kickoff','Kick off meeting','Test Plan','Defect Manage','Test Deliverable','Regression Testing','Release Notes','Deployment Prep','Go-live Checklist','Post-launch Review'];
  const PHASES=['Product Engineering','Design Phase','Development Phase','Quality Assurance'];
  // Small logo-style image swatches — flat colour + initial, sized to
  // sit comfortably within the row height rather than a generic
  // attachment/paperclip icon, since this column renders actual images.
  const LOGOS=[
    {bg:'#4A154B',t:'S'},{bg:'#0061FE',t:'D'},{bg:'#1DB954',t:'P'},{bg:'#FF4500',t:'R'},
    {bg:'#E01E5A',t:'G'},{bg:'#00A1E0',t:'C'},{bg:'#F2994A',t:'A'},{bg:'#7B61FF',t:'F'},
    {bg:'#0A66C2',t:'L'},{bg:'#EA4335',t:'M'}
  ];
  function logo(ri){
    const l=LOGOS[ri%LOGOS.length];
    return `<span class="pt-logo" style="background:${l.bg}">${l.t}</span>`;
  }
  const IC_CHECK='<svg viewBox="0 0 16 16" width="10" height="10" fill="none" stroke="currentColor" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><path d="M3.5 8.5l3 3 6-7"/></svg>';
  const FLAG='🇮🇳';

  // Tag pill: full-opacity fill of the category's primary colour, text
  // colour auto-inverts based on the primary's lightness (same --pN-text
  // tokens the auto-contrast checkbox/button already use).
  function pill(text,pIdx){
    return `<span class="pt-pill" style="background:var(--p${pIdx});color:var(--p${pIdx}-text)">${text}</span>`;
  }
  function stars(n){
    let out='<span class="pt-stars">';
    for(let i=0;i<5;i++)out+=`<svg width="11" height="11" viewBox="0 0 20 20" class="pt-star${i<n?'':' empty'}"><path d="M10 1.5l2.6 5.4 5.9.8-4.3 4.2 1 5.9-5.2-2.8-5.2 2.8 1-5.9L1.5 7.7l5.9-.8Z"/></svg>`;
    out+='</span>';
    return out;
  }
  // Both "Number Slider" and "Percent Complete" are slider-style
  // columns: light-gray track (--out2), solid primary fill up to the
  // handle, and a solid primary handle with a light halo ring — value
  // label reads in plain (non-primary) bold text, per the reference.
  function slider(pct,suffix){
    return `<span class="pt-slider"><span class="pt-slider-fill" style="width:${pct}%"></span><span class="pt-slider-handle" style="left:${pct}%"></span></span><span class="pt-slider-val">${pct}${suffix||''}</span>`;
  }
  function bar(pct){
    return `<span class="pt-bar"><span class="pt-bar-fill" style="width:${pct}%"></span></span>${pct}%`;
  }
  function check(on){
    return `<span class="pt-check ${on?'on':'off'}">${on?IC_CHECK:''}</span>`;
  }

  TASKS.forEach((task,ri)=>{
    const phaseIdx=ri%PHASES.length,phase2Idx=(ri+1)%PHASES.length;
    const phase=PHASES[phaseIdx],phase2=PHASES[phase2Idx];
    // colour follows the category value itself (so "Quality Assurance"
    // is always the same colour), not the row index
    const pIdx1=phaseIdx+1,pIdx2=phase2Idx+1,pIdx3=((phaseIdx+2)%PHASES.length)+1;
    const num=10+((ri*13)%90);
    const rating=2+(ri%4);
    const checked=ri%3!==0;
    const pct1=15+((ri*17)%80);
    const pct2=10+((ri*23)%90);
    const of1=1+(ri%4),of2=of1+(ri%3)+1;
    const price=(39.99+ri*5.15).toFixed(2);
    const tr=document.createElement('tr');
    tr.innerHTML=`
      <td><span class="pt-rowcheck"></span></td>
      <td>${task}</td>
      <td>${FLAG} +91 ${90000+ri*1234}</td>
      <td>$${price}</td>
      <td>${slider(num)}</td>
      <td>${stars(rating)}</td>
      <td>${check(checked)}</td>
      <td>${pct1}%</td>
      <td>${slider(pct2,'%')}</td>
      <td>${pill(phase,pIdx1)}</td>
      <td>${pill(phase,pIdx1)}${pill(phase2,pIdx2)}${ri%3===0?pill('+2',pIdx3):''}</td>
      <td><span style="margin-right:10px">${of1} of ${of2}</span>${bar(Math.round(of1/of2*100))}</td>
      <td>${logo(ri)}</td>
      <td><button class="pt-btn">Click here</button></td>
    `;
    body.appendChild(tr);
  });
})();

/* ── PowerTable module — "Kanban layout" ──
   Card chrome (bg/border/radius/shadow) reuses the same .visual
   element tokens as everywhere else; progress bar reuses --p1/--out2
   like the table layout's sliders; assignee pill reuses structural
   subtle-fill. Stack-status colours (Not Started/In Progress/Scrapped/
   Completed) and the Medium/Low priority colours are PROVISIONAL —
   only "Not Started"/"High Priority" (primaryColors[0]) and "Scrapped"
   (semantic.negative) were confidently readable from the reference;
   the rest use a neutral placeholder pending confirmation. */
(function(){
  const root=document.getElementById('ptKanban');
  if(!root)return;

  const AV='<svg viewBox="0 0 20 20" width="8" height="8" fill="currentColor"><circle cx="10" cy="7" r="4"/><path d="M2 18c0-4.4 3.6-8 8-8s8 3.6 8 8"/></svg>';
  function bar(pct){
    return `<span class="pt-bar"><span class="pt-bar-fill" style="width:${pct}%"></span></span>${pct}%`;
  }
  function card(title,priority,pStyle,done){
    return `<div class="pt-card">
      <div class="pt-card-title${done?' done':''}">${title}</div>
      <div class="pt-card-row"><span class="lbl">ID</span><span class="val">433654743920</span></div>
      <div class="pt-card-row"><span class="lbl">Priority</span><span class="val">${done?priority:`<span class="pt-pill" style="${pStyle}">${priority}</span>`}</span></div>
      <div class="pt-card-row"><span class="lbl">Assignee</span><span class="val"><span class="pt-assignee-pill"><span class="av">${AV}</span>Kat Larsson</span></span></div>
      <div class="pt-card-row"><span class="lbl">Date</span><span class="val">Jan 10 - Jan 22<span class="pt-date-sep"></span>4d</span></div>
      <div class="pt-card-row"><span class="lbl">Progress</span><span class="val">${bar(20)}</span></div>
    </div>`;
  }
  const HIGH_STYLE='background:var(--p1);color:var(--p1-text)';
  const MED_STYLE='background:var(--p2);color:var(--p2-text)';
  // Stack chips use the theme primaries in order: Not Started, In
  // Progress, Completed, Scrapped -> p1, p2, p3, p4.
  const NOTSTARTED_STYLE='background:var(--p1);color:var(--p1-text)';
  const INPROGRESS_STYLE='background:var(--p2);color:var(--p2-text)';
  const COMPLETED_STRIP_STYLE='background:var(--p3);color:var(--p3-text)';
  const SCRAPPED_STYLE='background:var(--p4);color:var(--p4-text)';

  // Inline width/height/flex styles on every small icon here — a
  // pre-existing rule (.visual.flex-fill svg{height:100%;flex:1}),
  // meant for full-size chart SVGs elsewhere, has higher specificity
  // than plain utility classes and would otherwise stretch these
  // small icons to fill the whole card height.
  const ICSTYLE='width:14px;height:14px;flex:none;display:inline-block';
  function stackHead(label,count,style){
    return `<div class="pt-stack-head">
      <span class="pt-stack-badge" style="${style}">${label}<span style="opacity:.85">${count}</span></span>
      <span class="pt-stack-space"></span>
      <svg class="pt-stack-icon" style="${ICSTYLE}" viewBox="0 0 20 20" fill="none" stroke="currentColor" stroke-width="1.6" stroke-linecap="round" stroke-linejoin="round"><path d="M10 4v12M4 10h12"/></svg>
      <svg class="pt-stack-icon" style="${ICSTYLE}" viewBox="0 0 20 20" fill="currentColor"><circle cx="10" cy="4.5" r="1.4"/><circle cx="10" cy="10" r="1.4"/><circle cx="10" cy="15.5" r="1.4"/></svg>
    </div>`;
  }
  function groupHead(label,count){
    return `<div class="pt-group-head">
      <svg class="chev" style="width:11px;height:11px;flex:none;display:inline-block" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"><path d="M2 4l4 4 4-4"/></svg>
      ${label}<span class="cnt">${count}</span>
      <span class="sp"></span>
      <svg class="kebab" style="width:13px;height:13px;flex:none;display:inline-block" viewBox="0 0 20 20" fill="currentColor"><circle cx="10" cy="4.5" r="1.4"/><circle cx="10" cy="10" r="1.4"/><circle cx="10" cy="15.5" r="1.4"/></svg>
    </div>`;
  }
  const addCard=`<div class="pt-add-card"><svg style="${ICSTYLE}" viewBox="0 0 20 20" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"><path d="M10 4v12M4 10h12"/></svg></div>`;
  // One shared "High Priority" swimlane header replaces the three
  // separate per-stack group headers (Not Started's, In Progress's,
  // and Scrapped's mislabeled "Completed") that all pointed at the
  // same tier — it spans the full board width above the columns.
  function swimlaneHead(label,count){
    return `<div class="pt-swimlane-head">
      <svg class="chev" style="width:12px;height:12px;flex:none;display:inline-block" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"><path d="M2 4l4 4 4-4"/></svg>
      ${label}<span class="cnt">${count}</span>
      <span class="sp"></span>
      <svg class="kebab" style="width:13px;height:13px;flex:none;display:inline-block" viewBox="0 0 20 20" fill="currentColor"><circle cx="10" cy="4.5" r="1.4"/><circle cx="10" cy="10" r="1.4"/><circle cx="10" cy="15.5" r="1.4"/></svg>
    </div>`;
  }

  // Layout is 3 stacked full-width rows sharing the same column
  // widths (300/300/40/300/auto), so everything lines up:
  //   1) chip row      — the four status badges + Add Stack
  //   2) swimlane head — single "High Priority" accordion, in
  //                      between the chips and the cards
  //   3) cards row     — each stack's card groups; the Completed
  //                      strip here is just the vertical label,
  //                      no chevron (that lives in the chip row)
  root.innerHTML=`
    <div class="pt-chip-row">
      <div class="pt-chip-col">${stackHead('Not Started','12',NOTSTARTED_STYLE)}</div>
      <div class="pt-chip-col">${stackHead('In Progress','7',INPROGRESS_STYLE)}</div>
      <div class="pt-chip-col pt-chip-col-narrow">
        <div class="pt-completed-chev">
          <svg style="width:14px;height:14px;flex:none;display:inline-block" viewBox="0 0 20 20" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"><path d="M4 4l5 6-5 6M11 4l5 6-5 6"/></svg>
        </div>
      </div>
      <div class="pt-chip-col">${stackHead('Scrapped','2',SCRAPPED_STYLE)}</div>
      <div class="pt-add-stack">
        <svg style="width:15px;height:15px;flex:none;display:inline-block" viewBox="0 0 20 20" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"><path d="M10 4v12M4 10h12"/></svg>
        Add Stack
      </div>
    </div>
    ${swimlaneHead('High Priority','20')}
    <div class="pt-kanban-row">
    <div class="pt-stack">
      <div class="pt-group">
        ${card('Feature Improvement Discussion with Project Manager','High Priority',HIGH_STYLE)}
        ${card('Cross-team Collaboration Meeting with PM','High Priority',HIGH_STYLE)}
        ${card('Market Insight Sharing with Project Manager','High Priority',HIGH_STYLE)}
        ${addCard}
      </div>
    </div>
    <div class="pt-stack">
      <div class="pt-group">
        ${card('Project Milestone Review and Next Steps with PM','High Priority',HIGH_STYLE)}
        ${card('Team Alignment Meeting with Project Manager','High Priority',HIGH_STYLE)}
        ${card('Cross-team Collaboration Meeting with PM','High Priority',HIGH_STYLE)}
        ${addCard}
      </div>
    </div>
    <div class="pt-completed-strip">
      <span class="lbl" style="${COMPLETED_STRIP_STYLE}">Completed</span>
      <span style="font-size:11px;color:var(--text-color);opacity:.6">2</span>
    </div>
    <div class="pt-stack">
      <div class="pt-group">
        ${card('Sprint Planning and Strategy Discussion with Project Manager','High Priority',HIGH_STYLE)}
        ${addCard}
      </div>
    </div>
    </div>
    ${swimlaneHead('Medium Priority','6')}
    <div class="pt-kanban-row">
    <div class="pt-stack">
      <div class="pt-group">
        ${card('Feature Improvement Discussion with Project Manager','Medium',MED_STYLE)}
        ${card('Market Insight Sharing with Project Manager','Medium',MED_STYLE)}
        ${addCard}
      </div>
    </div>
    <div class="pt-stack">
      <div class="pt-group">
        ${card('Project Milestone Review and Next Steps with PM','Medium',MED_STYLE,true)}
        ${card('Cross-team Collaboration Meeting with PM','Medium',MED_STYLE)}
        ${card('Team Alignment Meeting with Project Manager','Medium',MED_STYLE)}
        ${addCard}
      </div>
    </div>
    <div class="pt-completed-strip">
      <span class="lbl" style="${COMPLETED_STRIP_STYLE}">Completed</span>
      <span style="font-size:11px;color:var(--text-color);opacity:.6">0</span>
    </div>
    <div class="pt-stack">
      <div class="pt-group">
        ${card('Sprint Planning and Strategy Discussion with Project Manager','Medium',MED_STYLE)}
        ${addCard}
      </div>
    </div>
    </div>
  `;
})();

/* ── PowerTable module — "Gantt layout" ──
   Info columns (checkbox/Task Name/Single Select/Currency) are a
   sticky-left frozen panel; the timeline is a single relatively
   positioned strip per row with bars/milestones absolutely placed
   by month. Bar fill = solid var(--p1); remainder = same var(--p1)
   at reduced opacity (see CSS) — a "single primary" progress-bar
   look, not a second distinct color. Milestone diamonds and the
   "today" line both use var(--p3), per chat. */
(function(){
  const root=document.getElementById('ptGantt');
  if(!root)return;
  const MONTH_W=92; // px per month column
  const MONTHS=['January','February','March','April','May','June','July','August','September','October','November','December'];
  const PHASES=['Product Engineering','Design Phase','Development Phase','Quality Assurance'];
  function pill(phase){
    const idx=PHASES.indexOf(phase)+1||1;
    return `<span class="pt-pill" style="background:var(--p${idx});color:var(--p${idx}-text)">${phase}</span>`;
  }
  const L=m=>((m-1)*MONTH_W).toFixed(1); // left px for 1-based (possibly fractional) month
  const W=(a,b)=>((b-a)*MONTH_W).toFixed(1);
  // Exact organic capsule outline supplied for summary/parent bars —
  // stretched via preserveAspectRatio="none" to fit each bar's own
  // left/width, colored through the theme's primary via CSS (not a
  // hardcoded fill), rather than approximated with CSS shapes.
  const SUMMARY_BAR_SVG=`<svg viewBox="0 0 494 10" preserveAspectRatio="none"><path d="M489.836 8.6046L489.674 8.37188C489.299 7.83428 488.685 7.51411 488.03 7.51484L106.225 7.93971L5.84388 7.49307C5.24164 7.49039 4.67025 7.75924 4.2884 8.22495L3.54658 9.12967C2.3555 10.5823 0 9.74008 0 7.86156V2.13772C0 1.03315 0.89543 0.137718 2 0.137718H106.28L491.476 0.000225856C492.581 -0.00016851 493.477 0.895376 493.477 2.00022V7.46164C493.477 9.41955 490.955 10.2113 489.836 8.6046Z" style="fill:var(--p1)"/></svg>`;

  function timelineHead(){
    let year=`<div class="pt-gantt-year" style="left:0;width:${MONTH_W*12}px">2023</div>`;
    let q='';
    for(let i=0;i<4;i++)q+=`<div class="pt-gantt-quarter" style="left:${L(i*3+1)}px;width:${W(i*3+1,i*3+4)}px">Q${i+1}</div>`;
    let mo='';
    MONTHS.forEach((m,i)=>{mo+=`<div class="pt-gantt-month" style="left:${L(i+1)}px;width:${MONTH_W}px">${m}</div>`;});
    return `<div class="pt-gantt-row head">
      <div class="pt-gantt-info"><div class="chk"></div><div class="name">Task Name</div><div class="sel">Single Select</div><div class="cur">Currency</div></div>
      <div class="pt-gantt-timeline" style="width:${MONTH_W*12}px">${year}${q}${mo}</div>
    </div>`;
  }
  // bar: {type:'task'|'summary', start, end, progress} | null ; milestoneAt: month number | null
  // Milestones sit a clear 0.3-month gap before their bar starts so
  // the diamond never touches the bar edge.
  function ganttRow(name,phase,currency,bar,milestoneAt){
    let tl='';
    if(bar){
      const left=L(bar.start), width=W(bar.start,bar.end);
      if(bar.type==='summary'){
        tl+=`<div class="pt-gantt-bar summary" style="left:${left}px;width:${width}px">${SUMMARY_BAR_SVG}</div>`;
      }else{
        const fillPct=Math.round((bar.progress||0.5)*100);
        tl+=`<div class="pt-gantt-bar" style="left:${left}px;width:${width}px">
          <div class="fill" style="width:${fillPct}%"></div>
          <div class="rem"></div>
        </div>`;
      }
    }
    if(milestoneAt!=null){
      tl+=`<div class="pt-gantt-milestone" style="left:${(parseFloat(L(milestoneAt))-6).toFixed(1)}px"></div>`;
    }
    return `<div class="pt-gantt-row">
      <div class="pt-gantt-info">
        <div class="chk"><input type="checkbox"></div>
        <div class="name">${name}</div>
        <div class="sel">${pill(phase)}</div>
        <div class="cur">${currency}</div>
      </div>
      <div class="pt-gantt-timeline" style="width:${MONTH_W*12}px">${tl}</div>
    </div>`;
  }
  // Dependency elbow: Requirements Gathering -> Walkthrough & Ideation
  // (rows 2 and 4 below), drawn as one absolutely positioned SVG
  // overlaid on the timeline column, spanning those two row heights.
  const ROW_H=33, DEP_ROWS=2; // spans rows 2..3 (index 1,2 after header)
  function depArrow(){
    const x=L(4.3)-0, y1=ROW_H*0.5, y2=ROW_H*2+ROW_H*0.5;
    const x2=L(4.6);
    return `<div class="pt-gantt-dep" style="left:0;top:0;width:${x}px;height:${(ROW_H*3)}px">
      <svg width="100%" height="100%" style="overflow:visible" viewBox="0 0 ${x} ${ROW_H*3}">
        <path d="M${x-4} ${y1} H${x-40} V${y2} H${x2-parseFloat(x)+ (x-4)}" fill="none" stroke="var(--struct-icon)" stroke-width="1.4"/>
        <path d="M${x-16} ${y2-4} l10 4 l-10 4" fill="none" stroke="var(--struct-icon)" stroke-width="1.4"/>
      </svg>
    </div>`;
  }

  const bodyRowsHtml=[
    ganttRow('Gantt Product Engineering','Product Engineering','$39.99',{type:'summary',start:4,end:9.5}),
    ganttRow('Requirements Gathering','Product Engineering','$72.25',{type:'task',start:4.3,end:6.3,progress:0.55},4.0),
    ganttRow('Project Plan','Product Engineering','$58.75',{type:'task',start:7.2,end:9.3,progress:0.5}),
    ganttRow('Walkthrough & Ideation','Product Engineering','$45.00',{type:'task',start:4.6,end:6.6,progress:0.5}),
    ganttRow('Design Phase Kick off','Design Phase','$49.99',null),
    ganttRow('Business case study','Design Phase','$67.50',{type:'summary',start:1,end:6.2}),
    ganttRow('Systems architecture','Design Phase','$55.00',{type:'task',start:1.6,end:2.6,progress:0.55}),
    ganttRow('Ux Brainstorm','Design Phase','$42.50',{type:'task',start:3.6,end:5.3,progress:0.4}),
    ganttRow('UI Implementation','Design Phase','$60.00',{type:'task',start:1.3,end:3.3,progress:0.55}),
    ganttRow('Feedbacks & Review','Design Phase','$63.00',{type:'task',start:3.9,end:6.0,progress:0.35}),
    ganttRow('Dev handoff','Design Phase','$70.00',null),
    ganttRow('Development Kickoff','Development Phase','$48.99',null),
    ganttRow('Environment Setup','Development Phase','$62.75',{type:'task',start:2.0,end:3.4,progress:0.5},1.7),
    ganttRow('Internal Audit','Development Phase','$68.90',{type:'task',start:3.9,end:6.0,progress:0.45}),
    ganttRow('Back-end Development','Development Phase','$53.25',{type:'task',start:7.1,end:8.1,progress:0.55},6.8),
    ganttRow('Front-end Development','Development Phase','$44.40',{type:'task',start:8.2,end:9.9,progress:0.5}),
    ganttRow('Development Review','Development Phase','$69.99',{type:'summary',start:4,end:11.9}),
    ganttRow('Quality Assurance Kickoff','Quality Assurance','$54.50',{type:'task',start:2.0,end:4.0,progress:0.5},1.7),
    ganttRow('Kick off meeting','Quality Assurance','$59.99',{type:'task',start:6.9,end:9.0,progress:0.35}),
    ganttRow('Test Plan','Quality Assurance','$50.50',{type:'task',start:8.9,end:9.9,progress:0.45},8.6),
    ganttRow('Defect Manage','Quality Assurance','$65.00',{type:'task',start:9.9,end:11.0,progress:0.5}),
    ganttRow('Test Deliverable','Quality Assurance','$47.30',null)
  ];
  const ROW_HEIGHT=33, bodyHeight=bodyRowsHtml.length*ROW_HEIGHT;
  // A single continuous today-line spans the *entire* body height as
  // a sibling of the rows (not per-row), so scrolling never cuts it
  // and it never draws over the header. No vertical month gridlines
  // in the white body area — only the header shows column divisions.
  const todayLine=`<div class="pt-gantt-today" style="left:${L(7)}px;height:${bodyHeight}px"></div>`;

  root.innerHTML=`
    ${timelineHead()}
    <div class="pt-gantt-body" id="ptGanttBody">
      ${todayLine}
      ${bodyRowsHtml.join('')}
    </div>
  `;
  // Overlay the dependency arrow onto row 2's timeline cell (index 1
  // among body rows, i.e. the 2nd .pt-gantt-row after the header).
  const rows=root.querySelectorAll('.pt-gantt-row:not(.head)');
  if(rows[1]){
    const tl=rows[1].querySelector('.pt-gantt-timeline');
    if(tl){tl.style.overflow='visible';tl.insertAdjacentHTML('beforeend',depArrow());}
  }
})();

/* ── PowerTable module — "Calendar view" ──
   Task events: var(--p1), same as every other layout's task color.
   Milestone events: bordered/tinted p1 box + a p3 diamond, matching
   the Gantt milestone convention. Past/cancelled events: neutral
   gray + strikethrough, visually distinct from active theme color. */
(function(){
  const root=document.getElementById('ptCalendar');
  if(!root)return;
  const HOUR_H=60, DAY_W=190;
  const DAYS=[
    {num:'08',dow:'Sunday',weekend:true},
    {num:'09',dow:'Monday'},
    {num:'10',dow:'Tuesday'},
    {num:'11',dow:'Wednesday'},
    {num:'12',dow:'Thursday'},
    {num:'13',dow:'Friday'},
    {num:'14',dow:'Saturday',weekend:true}
  ];
  function hourLabel(h){
    if(h===0)return '12 AM';
    if(h<12)return h+' AM';
    if(h===12)return '12 PM';
    return (h-12)+' PM';
  }
  function evt(dayIdx,startH,endH,cls,title,rangeText,milestone,tooltip){
    const top=startH*HOUR_H, height=(endH-startH)*HOUR_H;
    const diamond=milestone?'<span class="diamond"></span>':'';
    const body=milestone
      ? `${diamond}<span><span class="t">${title}</span><br><span class="r">${rangeText}</span></span>`
      : `<div class="t">${title}</div><div class="r">${rangeText}</div>`;
    const attrs=tooltip?` data-tip-title="${title}" data-tip-range="${rangeText}"`:'';
    return {dayIdx,html:`<div class="pt-cal-event ${cls}"${attrs} style="top:${top}px;height:${height}px">${body}</div>`};
  }
  const EVENTS=[
    evt(0,1.5,2.5,'done','Back-end Development','1:30 AM - 2:30 AM'),
    evt(1,1.5,2.5,'done','Back-end Development','1:30 AM - 2:30 AM'),
    evt(2,2,4,'task','Back-end Development','2:00 AM - 4:00 AM'),
    evt(3,3,5,'task','Test Deliverable','03:00 AM to 05:00 AM',false,true),
    evt(5,2,4,'milestone','Environment Setup','2:00am - 4:00am',true),
    evt(6,2,4,'milestone','Environment Setup','2:00am - 4:00am',true)
  ];
  let head=`<div class="pt-cal-hourgutter"></div>`;
  DAYS.forEach(d=>{head+=`<div class="pt-cal-daycol-head"><div class="num">${d.num}</div><div class="dow">${d.dow}</div></div>`;});

  let hours='';
  for(let h=0;h<24;h++)hours+=`<div class="pt-cal-hour">${hourLabel(h)}</div>`;

  let cols='';
  DAYS.forEach((d,i)=>{
    let lines='';
    for(let h=0;h<24;h++)lines+=`<div class="pt-cal-hourline"></div>`;
    const dayEvents=EVENTS.filter(e=>e.dayIdx===i).map(e=>e.html).join('');
    cols+=`<div class="pt-cal-daycol${d.weekend?' weekend':''}">${lines}${dayEvents}</div>`;
  });

  root.innerHTML=`
    <div class="pt-cal-headrow">${head}</div>
    <div class="pt-cal-body">
      <div class="pt-cal-hours">${hours}</div>
      ${cols}
    </div>
  `;

  // Tooltip only appears on hover of its event (not permanently
  // visible) — one shared tooltip element repositioned per-event.
  const tip=document.createElement('div');
  tip.className='pt-cal-tooltip';
  const bodyEl=root.querySelector('.pt-cal-body');
  (bodyEl||root).appendChild(tip);
  root.querySelectorAll('.pt-cal-event[data-tip-title]').forEach(el=>{
    el.addEventListener('mouseenter',()=>{
      tip.innerHTML=`<div class="t">${el.dataset.tipTitle}</div><div>${el.dataset.tipRange}</div>`;
      const evtTop=parseFloat(el.style.top)||0;
      const col=el.closest('.pt-cal-daycol');
      const colLeft=col?col.offsetLeft:0;
      tip.style.left=colLeft+'px';
      tip.style.top=Math.max(0,evtTop-64)+'px';
      tip.classList.add('show');
    });
    el.addEventListener('mouseleave',()=>tip.classList.remove('show'));
  });
})();

/* ── PowerTable module — "Gantt resources" layout ──
   Grouped by Employee Name: each group has a per-day "hours worked"
   summary bar (var(--p2)) and, below it, task bars (var(--p1))
   positioned across the same day columns — a Gantt chart reshaped
   into a resource-calendar grouping, per chat/reference screenshot. */
(function(){
  const root=document.getElementById('ptGanttRes');
  if(!root)return;
  const COL_W=160;
  const COLS=[
    {label:'0',month:'June 2025'},
    {label:'Tue 2',month:'July 2025'},
    {label:'Wed 3'},
    {label:'Thu 4'},
    {label:'Fri 6'},
    {label:'Sat 7'},
    {label:'Sun 8'},
    {label:'Mon 9'}
  ];
  const MAX_H=9; // hours — tallest bar (Bob John, Fri 6) fills 100%
  const L=i=>i*COL_W;

  function headRow(){
    // Month super-header: spans col0 alone (June), then col1..7 (July).
    let months=`<div class="ptgr-col month" style="flex:0 0 ${COL_W}px">June 2025</div>`+
      `<div class="ptgr-col month" style="flex:0 0 ${COL_W*7}px">July 2025</div>`;
    let days='';
    COLS.forEach(c=>{days+=`<div class="ptgr-col dow" style="flex:0 0 ${COL_W}px">${c.label}</div>`;});
    return `<div class="ptgr-row head">
      <div class="ptgr-info">Grouped by<br>Employee&nbsp; Name</div>
      <div class="ptgr-timeline" style="flex-direction:column">
        <div style="display:flex">${months}</div>
        <div style="display:flex">${days}</div>
      </div>
    </div>`;
  }
  function hoursRow(name,hours){
    let cols='';
    hours.forEach(h=>{
      const pct=Math.max(6,Math.round((h/MAX_H)*100)); // column height %, floor so 0h still shows a sliver
      cols+=`<div class="ptgr-col" style="flex:0 0 ${COL_W}px">
        <div class="ptgr-hour-cell">
          <div class="ptgr-hour-bar" style="height:${pct}%"></div>
          <div class="ptgr-hour-lbl">${h?h+'h':(h===0?'0':'0h')}</div>
        </div>
      </div>`;
    });
    return `<div class="ptgr-row group">
      <div class="ptgr-info"><svg class="chev" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"><path d="M2 4l4 4 4-4"/></svg>${name}</div>
      <div class="ptgr-timeline">${cols}</div>
    </div>`;
  }
  // tasks: [{start, end, label}] where start/end are column-fraction
  // positions (e.g. 1.1 to 2.85 = starting a bit into Tue2, ending
  // just before Thu4).
  function taskRow(tasks,rowH){
    const height=rowH*40+10;
    let bars='';
    tasks.forEach((t,i)=>{
      const left=L(t.start), width=L(t.end)-L(t.start), top=t.row*40+8;
      bars+=`<div class="ptgr-taskbar" style="left:${left}px;width:${width}px;top:${top}px">${t.label}</div>`;
    });
    return `<div class="ptgr-row">
      <div class="ptgr-info"></div>
      <div class="ptgr-timeline"><div class="ptgr-taskarea" style="width:${COL_W*COLS.length}px;height:${height}px">${bars}</div></div>
    </div>`;
  }

  root.innerHTML=`
    ${headRow()}
    ${hoursRow('Alice Smith',[0,3,3,3,6,3,3,3])}
    ${taskRow([
      {start:1.15,end:2.9,label:'Alice Smith - Design API Endpoints',row:0},
      {start:2.15,end:3.9,label:'Alice Smith - Implement Authorization',row:0},
      {start:3.15,end:4.9,label:'Alice Smith - Test  Endpoints',row:1},
      {start:4.2,end:5.9,label:'Alice Smith - Review',row:2}
    ],3)}
    ${hoursRow('Bob john',[0,3,3,6,9,3,3,3])}
    ${taskRow([
      {start:2.2,end:3.9,label:'Bob john - Write Test Cases',row:0},
      {start:3.15,end:5.75,label:'Bob john - Bug repoting',row:1},
      {start:1.1,end:3.9,label:'Bob john - Execute Test Cases',row:2}
    ],3)}
    ${hoursRow('Carla Diaz',[0,6,6,3,3,3,0,3])}
    ${taskRow([
      {start:1.1,end:3.9,label:'Carla Diaz - Database Schema Design',row:0},
      {start:3.15,end:4.9,label:'Carla Diaz - Migration Scripts',row:1},
      {start:4.2,end:5.9,label:'Carla Diaz - Code Review',row:1},
      {start:7.15,end:7.9,label:'Carla Diaz - Release Notes',row:2}
    ],3)}
    ${hoursRow('David Lee',[0,3,6,6,3,3,3,3])}
    ${taskRow([
      {start:1.15,end:2.9,label:'David Lee - Sprint Planning',row:0},
      {start:2.15,end:4.9,label:'David Lee - Backend Integration',row:1},
      {start:4.2,end:5.9,label:'David Lee - Performance Tuning',row:2}
    ],3)}
    ${hoursRow('Emma Wright',[0,3,3,3,3,6,6,3])}
    ${taskRow([
      {start:1.15,end:3.9,label:'Emma Wright - UX Research',row:0},
      {start:4.15,end:5.9,label:'Emma Wright - Prototype Review',row:1},
      {start:5.2,end:6.9,label:'Emma Wright - Usability Testing',row:1},
      {start:6.15,end:7.9,label:'Emma Wright - Handoff Documentation',row:2}
    ],3)}
  `;
})();

/* ── Planning "Tree view" ──
   Root "All" card fans out via curved connectors to one card per
   product category — realistic Sum of Sales / Sum of Profit figures
   (in the same domain as the Planning matrix: Region>Country>
   Category>Sub-Category), not the placeholder "Course-N" data from
   the reference screenshot. */
(function(){
  const root=document.getElementById('planTree');
  if(!root)return;
  const CATS=[
    {name:'Electronics',sales:482.3,profit:86.4},
    {name:'Furniture',sales:210.5,profit:38.9},
    {name:'Office Supplies',sales:96.7,profit:17.2},
    {name:'Personal Care',sales:143.2,profit:25.6},
    {name:'Apparel',sales:305.8,profit:54.3},
    {name:'Footwear',sales:178.4,profit:31.0},
    {name:'Home Appliances',sales:264.9,profit:47.8},
    {name:'Sporting Goods',sales:132.6,profit:22.4},
    {name:'Beauty & Wellness',sales:198.3,profit:35.6},
    {name:'Automotive Accessories',sales:87.5,profit:15.8}
  ];
  const totalSales=CATS.reduce((s,c)=>s+c.sales,0);
  const totalProfit=CATS.reduce((s,c)=>s+c.profit,0);
  function fmt(v){return v>=1000?(v/1000).toFixed(2)+'M':v.toFixed(2)+'k';}

  const CARD_W=260, CARD_H=92, GAP_Y=16, GAP_X=90, LEFT_X=40;
  const rightX=LEFT_X+CARD_W+GAP_X;
  const totalH=CATS.length*CARD_H+(CATS.length-1)*GAP_Y;
  const rootY=Math.max(0,totalH/2-CARD_H/2);
  const topY=40;

  function card(x,y,title,rows,isRoot){
    return `<div class="plan-tree-card${isRoot?' root':''}" style="left:${x}px;top:${topY+y}px">
      <div class="hd">${title}</div>
      ${rows.map(r=>`<div class="row"><span class="lbl">${r[0]}</span><span class="val">${r[1]}</span></div>`).join('')}
    </div>`;
  }
  function bezier(x1,y1,x2,y2){
    const midX=(x1+x2)/2;
    return `<path d="M${x1} ${y1} C ${midX} ${y1}, ${midX} ${y2}, ${x2} ${y2}"/>`;
  }

  let cards=card(LEFT_X,rootY,'All',[['Sum of Sales','$'+fmt(totalSales)],['Sum of Profit','$'+fmt(totalProfit)]],true);
  let conns='';
  const rootCX=LEFT_X+CARD_W, rootCY=topY+rootY+CARD_H/2;
  CATS.forEach((c,i)=>{
    const y=i*(CARD_H+GAP_Y);
    cards+=card(rightX,y,c.name,[['Sum of Sales','$'+fmt(c.sales)],['Sum of Profit','$'+fmt(c.profit)]],false);
    const childCY=topY+y+CARD_H/2;
    conns+=bezier(rootCX,rootCY,rightX,childCY);
  });
  const countIcon=`<div class="plan-tree-count" style="left:${rootCX-10}px;top:${rootCY-10}px"><svg viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round"><path d="M7.5 2.5L3 6l4.5 3.5"/></svg></div>`;

  const totalWidth=rightX+CARD_W+60;
  const totalHeightPx=topY+Math.max(totalH,rootY+CARD_H)+40;
  root.style.width=totalWidth+'px';
  root.style.height=totalHeightPx+'px';
  root.innerHTML=`<svg class="plan-tree-conn" width="${totalWidth}" height="${totalHeightPx}">${conns}</svg>${cards}${countIcon}`;
})();

