/* ── Intelligence "Template" switcher ──
   Replaces the old clickable canvas page-switcher (Overview/Sales/
   Products/Planning) as the actual control for changing which of the
   four Intelligence report pages is shown — those canvas buttons are
   now a purely visual, non-interactive indicator (see the module
   switcher below, and the pointer-events:none rule on #pbtns). */
(function(){
  const pick=document.getElementById('intelLayoutPick');
  const btn=document.getElementById('intelLayoutBtn');
  const label=document.getElementById('intelLayoutLabel');
  const drop=document.getElementById('intelLayoutDrop');
  if(!pick||!btn||!drop)return;

  const LABELS={0:'Template 1',1:'Template 2',2:'Template 3',3:'Template 4'};
  window._intelShowLayoutPicker=function(show){
    pick.style.display=show?'block':'none';
  };
  window._intelSyncTemplate=function(idx){
    drop.querySelectorAll('.pt-layout-opt').forEach(o=>o.classList.toggle('active',parseInt(o.dataset.pg)===idx));
    label.textContent=LABELS[idx]||LABELS[0];
  };
  function selectTemplate(idx){
    if(typeof showPage==='function')showPage(idx);
    if(typeof window._setLastIntelligencePage==='function')window._setLastIntelligencePage(idx);
    window._intelSyncTemplate(idx);
    drop.classList.remove('open');
  }
  btn.addEventListener('click',e=>{e.stopPropagation();drop.classList.toggle('open');});
  drop.querySelectorAll('.pt-layout-opt').forEach(o=>o.addEventListener('click',()=>selectTemplate(parseInt(o.dataset.pg))));
  document.addEventListener('click',e=>{if(!pick.contains(e.target))drop.classList.remove('open');});
})();

/* ── Module switcher: Intelligence / Planning / PowerTable ──
   The side panel (colours, page, elements, font) always stays mounted
   and visible — it edits the one shared theme, so switching modules
   only swaps which report page is shown in the same canvas, exactly
   like the existing Overview/Sales/Products/Planning-page pivot does
   inside Intelligence. This keeps the "the theme is global" mental
   model consistent across all three module tabs. */
(function(){
  const MODULE_PAGE={intelligence:0,planning:4,powertable:5};
  const btns=Array.from(document.querySelectorAll('.mod-switch-btn'));
  let lastIntelligencePage=0;
  window._setLastIntelligencePage=function(idx){lastIntelligencePage=idx;};
  function selectModule(name){
    btns.forEach(b=>{
      const active=b.dataset.module===name;
      b.classList.toggle('active',active);
      b.setAttribute('aria-selected',active?'true':'false');
    });
    const pbtns=document.getElementById('pbtns');
    if(pbtns)pbtns.style.display=name==='intelligence'?'':'none';
    if(typeof showPage==='function'){
      showPage(name==='intelligence'?lastIntelligencePage:MODULE_PAGE[name]);
    }
    if(typeof window._ptShowLayoutPicker==='function')window._ptShowLayoutPicker(name==='powertable');
    if(typeof window._planShowLayoutPicker==='function')window._planShowLayoutPicker(name==='planning');
    if(typeof window._intelShowLayoutPicker==='function')window._intelShowLayoutPicker(name==='intelligence');
    if(name==='intelligence'&&typeof window._intelSyncTemplate==='function')window._intelSyncTemplate(lastIntelligencePage);
    if(typeof window._setVisualsTabEnabled==='function')window._setVisualsTabEnabled(name==='intelligence');
  }
  btns.forEach(b=>b.addEventListener('click',()=>selectModule(b.dataset.module)));
  // Default landing module is Planning. Deferred to the next tick since
  // showPage() depends on the PAGES const declared later in this script
  // (would otherwise throw a temporal-dead-zone ReferenceError if called
  // synchronously here, before that declaration has run).
  setTimeout(()=>selectModule('planning'),0);
})();

