/* ── Panel rail: click to open/switch tab; click active tab to collapse ── */
(function(){
  const app=document.querySelector('.app');
  const titleEl=document.getElementById('panelBodyTitle');
  const TAB_NAMES={colors:'Color',page:'Page',visuals:'Visuals',font:'Font'};
  let activeTab='colors';
  let panelOpen=true; // start open on Color

  function openTab(tab){
    activeTab=tab; panelOpen=true;
    document.querySelectorAll('.panel-rail-btn').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));
    $$('.tabpanel').forEach(t=>t.classList.remove('on'));
    $('#tp-'+tab).classList.add('on');
    if(titleEl)titleEl.textContent=TAB_NAMES[tab]||tab;
    app.classList.add('panel-open');
    requestAnimationFrame(fit); setTimeout(fit,240);
    setTimeout(()=>{if(window._toolbarReflow)_toolbarReflow();},260);
  }

  function closePanel(){
    panelOpen=false;
    app.classList.remove('panel-open');
    document.querySelectorAll('.panel-rail-btn').forEach(b=>b.classList.remove('active'));
    requestAnimationFrame(fit); setTimeout(fit,240);
    setTimeout(()=>{if(window._toolbarReflow)_toolbarReflow();},260);
  }


  document.querySelectorAll('.panel-rail-btn').forEach(btn=>{
    btn.addEventListener('click',()=>{
      if(btn.classList.contains('disabled'))return;
      const tab=btn.dataset.tab;
      if(panelOpen && activeTab===tab) closePanel();
      else openTab(tab);
    });
  });

  // The "Visuals" tab (element background/border/radius/shadow/
  // padding) only applies to Intelligence's chart/table widgets —
  // Planning's matrix and PowerTable's layouts are flat, full-bleed
  // page canvases with no such element styling, so that tab is
  // disabled while either of those modules is active. If it was the
  // open tab when switching away from Intelligence, fall back to
  // the Color tab instead of leaving an empty/disabled panel open.
  window._setVisualsTabEnabled=function(enabled){
    const btn=document.querySelector('.panel-rail-btn[data-tab="visuals"]');
    if(!btn)return;
    btn.classList.toggle('disabled',!enabled);
    btn.setAttribute('aria-disabled',enabled?'false':'true');
    if(!enabled && activeTab==='visuals'){
      if(panelOpen)openTab('colors'); else activeTab='colors';
    }
  };

  // Open Color tab by default on load
  openTab('colors');

  // ⌘B shortcut
  window._togglePanel=()=>{ panelOpen ? closePanel() : openTab(activeTab); };
  window._closePanel=closePanel;

  // Backdrop click (drawer mode only, see narrow-shell reflow below)
  const backdrop=document.getElementById('narrowShellBackdrop');
  if(backdrop)backdrop.addEventListener('click',()=>{ if(panelOpen)closePanel(); });

  /* Set initial active state */
  const btn=document.getElementById('ftbPanelToggle');
  if(btn)btn.classList.add('active');

/* ── Toolbar progressive disclosure (ResizeObserver) ── */
(function(){
  const ftb=document.getElementById('floatingToolbar');
  if(!ftb||!window.ResizeObserver)return;

  // Priority 4 = first to lose label, Priority 1 = last to lose label
  const HIDE_ORDER=[4,3,2,1];

  function getItems(p){return Array.from(ftb.querySelectorAll(`[data-priority="${p}"]`));}

  // Measure natural (unconstrained) total width of toolbar content.
  // We do this by measuring all direct children's offsetWidth,
  // but the flex-space div absorbs slack so we exclude it.
  function availableWidth(){return ftb.offsetWidth;}

  // Measure true unconstrained natural width.
  // Flex already compressed children, so we can't use offsetWidth directly.
  // Instead: measure each child's scrollWidth (uncompressed content width).
  // For the spacer we skip it. For separators/divs use offsetWidth (they're fixed).
  function naturalWidth(){
    let w=0;
    const style=getComputedStyle(ftb);
    w+=parseFloat(style.paddingLeft||0)+parseFloat(style.paddingRight||0);
    Array.from(ftb.children).forEach(el=>{
      if(el.classList.contains('ftb-space'))return;
      // scrollWidth gives the unconstrained content width even in a compressed flex item
      w+=el.scrollWidth;
    });
    return w;
  }

  function surplus(){return availableWidth()-naturalWidth();}

  function reflow(){
    // Step 1: restore ALL labels first so we measure full natural width
    ftb.querySelectorAll('[data-label-hidden]').forEach(el=>el.removeAttribute('data-label-hidden'));
    ftb.removeAttribute('data-compact');

    // Step 2: hide priority groups one by one until surplus >= 0
    // After each hide, naturalWidth() drops so we re-check accurately
    for(const p of HIDE_ORDER){
      if(surplus()>=-4)break;
      getItems(p).forEach(el=>el.setAttribute('data-label-hidden',''));
    }

    // Step 3: compact padding if still very tight after all labels hidden
    if(surplus()<-8)ftb.setAttribute('data-compact','');
  }

  const ro=new ResizeObserver(()=>requestAnimationFrame(reflow));
  ro.observe(ftb);
  window._toolbarReflow=reflow;

  // Scroll-discoverability fades: only show the left/right gradient
  // when there's actually more toolbar content off-screen that way.
  const wrap=document.getElementById('ftbWrap');
  if(wrap){
    function updateFades(){
      const max=ftb.scrollWidth-ftb.clientWidth;
      wrap.classList.toggle('can-scroll-left',ftb.scrollLeft>2);
      wrap.classList.toggle('can-scroll-right',ftb.scrollLeft<max-2);
    }
    ftb.addEventListener('scroll',()=>requestAnimationFrame(updateFades),{passive:true});
    ro.observe(wrap);
    const roFades=new ResizeObserver(()=>requestAnimationFrame(updateFades));
    roFades.observe(ftb);
    setTimeout(updateFades,50);
    window._toolbarUpdateFades=updateFades;
  }
})();

/* ── Module-switch pill row: scroll-discoverability fades ──
   Mirrors the toolbar's fade logic (see above) for the module-switch
   pill group, which can now scroll horizontally instead of clipping
   once the layout-switcher button beside it leaves it too little
   room on a narrow screen. */
(function(){
  const outer=document.getElementById('modSwitchOuter');
  const bar=document.getElementById('modSwitch');
  if(!outer||!bar)return;
  function updateFades(){
    const max=bar.scrollWidth-bar.clientWidth;
    outer.classList.toggle('can-scroll-left',bar.scrollLeft>2);
    outer.classList.toggle('can-scroll-right',bar.scrollLeft<max-2);
  }
  bar.addEventListener('scroll',()=>requestAnimationFrame(updateFades),{passive:true});
  if(window.ResizeObserver){
    const ro=new ResizeObserver(()=>requestAnimationFrame(updateFades));
    ro.observe(bar);
    ro.observe(outer);
  }
  setTimeout(updateFades,50);
  window._modSwitchUpdateFades=updateFades;
})();

/* ── Panel drawer/docked mode switch (ResizeObserver) ──
   Below NARROW_THRESHOLD px of total app-shell width, the side panel
   stops pushing the report canvas (docked mode) and instead floats
   over it as an overlay drawer with a click-to-dismiss backdrop, so
   narrow windows keep as much room as possible for the actual report. */
(function(){
  const app=document.querySelector('.app');
  if(!app||!window.ResizeObserver)return;
  const NARROW_THRESHOLD=900;
  let isNarrow=null;
  function reflow(){
    const narrow=app.offsetWidth<NARROW_THRESHOLD;
    if(narrow===isNarrow)return;
    isNarrow=narrow;
    app.classList.toggle('narrow-shell',narrow);
    if(typeof fit==='function'){requestAnimationFrame(fit);setTimeout(fit,240);}
  }
  const ro=new ResizeObserver(()=>requestAnimationFrame(reflow));
  ro.observe(app);
  reflow();
  window._shellReflow=reflow;
})();

  addEventListener('keydown',e=>{
    if((e.ctrlKey||e.metaKey)&&e.key.toLowerCase()==='b'){e.preventDefault();if(window._togglePanel)_togglePanel();}
    if((e.ctrlKey||e.metaKey)&&!e.shiftKey&&e.key.toLowerCase()==='z'){e.preventDefault();undoAction();}
    if((e.ctrlKey||e.metaKey)&&e.shiftKey&&e.key.toLowerCase()==='z'){e.preventDefault();redoAction();}
    if((e.ctrlKey||e.metaKey)&&e.key.toLowerCase()==='y'){e.preventDefault();redoAction();}
    if(e.key==='Escape'){document.querySelectorAll('.modal-bg.show').forEach(m=>m.classList.remove('show'));if(cbsimActive)cbsimHide();document.getElementById('ftbThemeDrop').classList.remove('open');
      const appEl=document.querySelector('.app');
      if(appEl&&appEl.classList.contains('narrow-shell')&&appEl.classList.contains('panel-open')&&window._closePanel)window._closePanel();
    }
  });
})();

/* ── Theme switcher dropdown ── */
(function(){
  const btn=document.getElementById('ftbThemeBtn');
  const drop=document.getElementById('ftbThemeDrop');
  const nameLbl=document.getElementById('ftbThemeName');

  const CHECK_SVG=`<svg width="8" height="8" viewBox="0 0 10 10" fill="none" stroke="#fff" stroke-width="2.2" stroke-linecap="round"><path d="M2 5l2.5 2.5L8 3"/></svg>`;
  const EDIT_SVG=`<svg viewBox="0 0 14 14" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round" width="11" height="11"><path d="M9.5 2l2.5 2.5L4 13H1.5v-2.5L9.5 2Z"/><path d="M7.5 4l2.5 2.5"/></svg>`;

  function makeCard(colors,canvasBg,label,isActive,onLoad,onEdit){
    const dark=isActive?false:canvasBg&&parseInt(canvasBg.slice(1),16)<0x808080*3;
    // heuristic: dark if canvas luminance low
    const [r,g,b]=[parseInt((canvasBg||'#fff').slice(1,3),16),parseInt((canvasBg||'#fff').slice(3,5),16),parseInt((canvasBg||'#fff').slice(5,7),16)];
    const isDark=(0.299*r+0.587*g+0.114*b)<128;
    const cols6=(colors||[]).slice(0,6);
    const heights=[42,68,52,80,58,72]; // vary heights for visual interest
    const bars=cols6.map((c,i)=>`<div class="ftd-col" style="height:${heights[i]%100}%;background:${c}"></div>`).join('');
    const card=document.createElement('div');
    card.className='ftd-card'+(isActive?' active':'');
    card.innerHTML=`
      <div class="ftd-check">${CHECK_SVG}</div>
      <div class="ftd-preview" style="background:${canvasBg||'#fff'}">${bars}</div>
      <div class="ftd-foot${isDark?' dk':''}">
        <div class="ftd-name${isDark?' lt':''}">${label}</div>
      </div>
      ${onEdit?`<button class="ftd-edit" title="Edit">${EDIT_SVG}</button>`:''}`;
    card.addEventListener('click',onLoad);
    if(onEdit){
      const eb=card.querySelector('.ftd-edit');
      if(eb)eb.addEventListener('click',e=>{e.stopPropagation();onEdit();});
    }
    return card;
  }

  function buildDrop(){
    drop.innerHTML='';

    // Search box
    const srch=document.createElement('div');srch.className='ftd-search';
    srch.innerHTML=`<svg width="12" height="12" viewBox="0 0 16 16" fill="none" stroke="#8a8886" stroke-width="1.5" stroke-linecap="round"><circle cx="6.5" cy="6.5" r="4.5"/><path d="M10 10l3.5 3.5"/></svg><input placeholder="Search themes…" id="ftdSearchInput">`;
    drop.appendChild(srch);
    const searchInput=srch.querySelector('input');
    searchInput.addEventListener('input',e=>{e.stopPropagation();renderCards(e.target.value.trim().toLowerCase());});
    searchInput.addEventListener('click',e=>e.stopPropagation());

    const container=document.createElement('div');container.id='ftdContainer';
    drop.appendChild(container);

    function loadPreset(p){
      T=JSON.parse(JSON.stringify(p));snapshotOrigin();buildAll();applyTheme();
      requestAnimationFrame(fit);checkDirty();updateDeleteBtn();
      if(nameLbl)nameLbl.textContent=p.label;
      drop.classList.remove('open');
    }
    function loadUser(item){
      T=JSON.parse(JSON.stringify(item));snapshotOrigin();buildAll();applyTheme();
      requestAnimationFrame(()=>requestAnimationFrame(fit));
      updateDeleteBtn();if(nameLbl)nameLbl.textContent=item.label||'Untitled';
      drop.classList.remove('open');
    }

    function renderCards(q){
      container.innerHTML='';
      // Built-in
      const filtered=PRESETS.filter(p=>!q||p.label.toLowerCase().includes(q));
      if(filtered.length){
        const sh=document.createElement('div');sh.className='ftd-section';sh.textContent='Built-in';container.appendChild(sh);
        const grid=document.createElement('div');grid.className='ftd-grid';
        filtered.forEach(p=>{
          const colors=(p.theme&&p.theme.colors&&p.theme.colors.primaryColors)||[];
          const bg=(p.theme&&p.theme.page&&p.theme.page.canvas&&p.theme.page.canvas.background&&p.theme.page.canvas.background.color)||'#fff';
          grid.appendChild(makeCard(colors,bg,p.label,T.label===p.label,()=>loadPreset(p),null));
        });
        container.appendChild(grid);
      }
      // Saved
      const lib=libLoad();
      const filteredLib=lib.filter(item=>!q||(item.label||'').toLowerCase().includes(q));
      if(filteredLib.length){
        const div=document.createElement('div');div.className='ftd-divider';container.appendChild(div);
        const uh=document.createElement('div');uh.className='ftd-section';uh.textContent='Saved';container.appendChild(uh);
        const ugrid=document.createElement('div');ugrid.className='ftd-grid';
        filteredLib.forEach((item,i)=>{
          const ucolors=(item.theme&&item.theme.colors&&item.theme.colors.primaryColors)||[];
          const ubg=(item.theme&&item.theme.page&&item.theme.page.canvas&&item.theme.page.canvas.background&&item.theme.page.canvas.background.color)||'#fff';
          const isActive=T.label===item.label&&!PRESETS.find(p=>p.label===T.label);
          ugrid.appendChild(makeCard(ucolors,ubg,item.label||'Untitled',isActive,()=>loadUser(item),()=>{drop.classList.remove('open');openWizardEdit(item,i);}));
        });
        container.appendChild(ugrid);
      }
      if(!filtered.length&&!filteredLib.length){
        const empty=document.createElement('div');empty.style.cssText='padding:16px;text-align:center;font-size:12px;color:#8a8886;font-family:var(--f-font)';empty.textContent='No themes match your search';container.appendChild(empty);
      }
    }

    renderCards('');
  }

  btn.addEventListener('click',e=>{
    e.stopPropagation();
    buildDrop();
    drop.classList.toggle('open');
    if(drop.classList.contains('open')){
      // Position relative to button using viewport coords (works with fixed)
      const r=btn.getBoundingClientRect();
      drop.style.top=(r.bottom+6)+'px';
      // Align left edge of dropdown with left edge of button, but clamp to viewport
      let left=r.left;
      const dw=Math.max(220,drop.offsetWidth||220);
      if(left+dw>window.innerWidth-8)left=window.innerWidth-dw-8;
      drop.style.left=Math.max(8,left)+'px';
    }
  });
  document.addEventListener('click',()=>drop.classList.remove('open'));

  /* Sync name label when theme loaded externally */
  const origApply=applyTheme;
  applyTheme=function(){origApply();if(nameLbl&&T.label)nameLbl.textContent=T.label;};
})();

/* ── Scale to fit both width AND height ── */
const stage=$('#stage'),scaler=$('#scaler'),report=$('#report');
const DESIGN_W=1160,DESIGN_H=780;
function fit(){
  const aw=stage.clientWidth-40;
  const ah=stage.clientHeight-40; /* 20 top + 20 bottom padding */
  const s=Math.min(aw/DESIGN_W,ah/DESIGN_H);
  scaler.style.transform='scale('+s+')';
  scaler.style.width=DESIGN_W+'px';
  scaler.style.height=DESIGN_H+'px';
}
addEventListener('resize',fit);

/* ── JSON import parsing (used by the New Theme wizard's "Import JSON"
   source — validates a pasted theme JSON and returns a clean {label,theme}
   object, or throws with a human-readable message on failure). ── */
function parseThemeJson(json){
  const obj=typeof json==='string'?JSON.parse(json):json;
  if(!obj||typeof obj!=='object')throw new Error('Not a valid JSON object');
  if(!obj.theme)throw new Error('Missing "theme" key');
  // Strip _meta so it doesn't affect token logic
  const {_meta,...themeData}=obj;
  const clean=JSON.parse(JSON.stringify(themeData));
  if(!clean.label||!clean.label.trim())clean.label='Imported Theme';
  return clean;
}

/* ══════════════════════════════════════════════════════════
   OKLCH COLOUR PIPELINE
══════════════════════════════════════════════════════════ */
function clamp(v,lo,hi){return Math.max(lo,Math.min(hi,v));}
function _lin(c){return c<=0.04045?c/12.92:Math.pow((c+0.055)/1.055,2.4);}
function _delin(c){if(c<=0)return 0;if(c>=1)return 255;return Math.round(255*(c<=0.0031308?12.92*c:1.055*Math.pow(c,1/2.4)-0.055));}
function hexToOklch(hex){
  const h=hex.replace('#','');
  const rl=_lin(parseInt(h.slice(0,2),16)/255),gl=_lin(parseInt(h.slice(2,4),16)/255),bl=_lin(parseInt(h.slice(4,6),16)/255);
  let l=Math.cbrt(0.4122214708*rl+0.5363325363*gl+0.0514459929*bl);
  let m=Math.cbrt(0.2119034982*rl+0.6806995451*gl+0.1073969566*bl);
  let s=Math.cbrt(0.0883024619*rl+0.2817188376*gl+0.6299787005*bl);
  const L=0.2104542553*l+0.7936177850*m-0.0040720468*s;
  const a=1.9779984951*l-2.4285922050*m+0.4505937099*s;
  const b=-0.0259040371*l+0.7827717662*m-0.8068517602*s;
  const C=Math.sqrt(a*a+b*b);
  const H=(Math.atan2(b,a)*180/Math.PI+360)%360;
  return[L,C,H];
}
function oklchToHex(L,C,H){
  const a=C*Math.cos(H*Math.PI/180),b=C*Math.sin(H*Math.PI/180);
  let l=L+0.3963377774*a+0.2158037573*b;
  let m=L-0.1055613458*a-0.0638541728*b;
  let s=L-0.0894841775*a-1.2914855480*b;
  l=l*l*l;m=m*m*m;s=s*s*s;
  let rl= 4.0767416621*l-3.3077115913*m+0.2309699292*s;
  let gl=-1.2684380046*l+2.6097574011*m-0.3413193965*s;
  let bl=-0.0041960863*l-0.7034186147*m+1.7076147010*s;
  rl=clamp(rl,0,1);gl=clamp(gl,0,1);bl=clamp(bl,0,1);
  return '#'+[_delin(rl),_delin(gl),_delin(bl)].map(x=>x.toString(16).padStart(2,'0')).join('').toUpperCase();
}
const ANCHORS=[0,51,122,176,215,258,300,340];
const L_OFFSETS=[0,+0.06,-0.06,+0.06,-0.06,+0.06,-0.06,+0.06];
const CHART_L_MIN=0.48,CHART_L_MAX=0.72;
function perceptualDist(h1,h2){
  let d=(h2-h1+360)%360;if(d>180)d=360-d;
  const mid=(h1+d/2)%360;
  const w=mid>=60&&mid<130?0.60:mid>=130&&mid<200?0.90:mid>=200&&mid<280?1.10:1.00;
  return d*w;
}
function buildHuePositions(brandH){
  const pos=ANCHORS.map(a=>(brandH+a)%360);
  for(let iter=0;iter<60;iter++){
    let minP=999,wi=-1;
    for(let i=0;i<8;i++){const pd=perceptualDist(pos[i],pos[(i+1)%8]);if(pd<minP){minP=pd;wi=i;}}
    if(minP>=25)break;
    const j=(wi+1)%8;
    if(wi===0)pos[j]=(pos[j]+2)%360;
    else if(j===0)pos[wi]=(pos[wi]-2+360)%360;
    else{pos[wi]=(pos[wi]-1+360)%360;pos[j]=(pos[j]+1)%360;}
  }
  return pos;
}
const RULES={
  primC_min:0.10,primC_cap:0.17,chartL_dark_boost:0.10,
  chromaInputFloor:0.06,chromaCap:0.17,struct_C:0.005,
  structL_subtleFill:0.98,structL_canvasBg:0.98,structL_elBg:0.98,
  structL_background:0.96,structL_outline2:0.88,structL_outline1:0.72,
  structL_subtleFill_dk:0.22,structL_canvasBg_dk:0.14,structL_elBg_dk:0.18,
  structL_background_dk:0.20,structL_outline2_dk:0.32,structL_outline1_dk:0.44,
  wallpaperC_light:0.008,wallpaperL_light:0.95,wallpaperL_dark:0.10,
  posH:145,posL_light:0.55,posC_light:0.18,posL_dark:0.70,posC_dark:0.20,
  negH_base:25,negL_light:0.52,negC_light:0.20,negL_dark:0.68,negC_dark:0.22,
  neuH:255,neuL_light:0.72,neuC_light:0.04,neuL_dark:0.68,neuC_dark:0.04,
};
function isAchromatic(C){return C<RULES.chromaInputFloor;}
function achromatic8(brandL,dark){
  const base=dark?0.65:0.55;
  return[-.30,-.20,-.10,0,+.10,+.20,+.30,+.38].map(s=>oklchToHex(clamp(base+s,0.15,0.92),0.01,0));
}
function negativeHue(brandH){
  const inOrangeZone=(brandH>=0&&brandH<=50)||(brandH>=330&&brandH<=360);
  return inOrangeZone?{H:5,Llight:0.45,Ldark:0.60,C:0.22}:{H:RULES.negH_base,Llight:RULES.negL_light,Ldark:RULES.negL_dark,C:RULES.negC_light};
}
function generateTheme(brandHex,tone,name){
  const[bL,bC,bH]=hexToOklch(brandHex);
  const dark=tone==='dark';
  const achro=isAchromatic(bC);
  let primaries;
  if(achro){primaries=achromatic8(bL,dark);}
  else{
    const baseL=dark?clamp(bL+RULES.chartL_dark_boost,CHART_L_MIN+0.08,CHART_L_MAX+0.10):clamp(bL,CHART_L_MIN,CHART_L_MAX);
    const pC=clamp(bC,RULES.primC_min,RULES.primC_cap);
    const huePositions=buildHuePositions(bH);
    primaries=huePositions.map((pos,i)=>{
      if(i===0)return brandHex.toUpperCase();
      return oklchToHex(clamp(baseL+L_OFFSETS[i],0.38,0.82),pC,pos);
    });
  }
  return themeFromPrimaries(primaries,tone,name,bH);
}

/* ── Build a full theme from an explicit 8-colour primaries array
     (shared by generateTheme() and generateThemeFromPalette()) ── */
function themeFromPrimaries(primaries,tone,name,seedHue){
  const bH=seedHue;
  const dark=tone==='dark';
  const struct=dark?{
    outline1:oklchToHex(RULES.structL_outline1_dk,0.006,220),
    outline2:oklchToHex(RULES.structL_outline2_dk,0.006,220),
    background:oklchToHex(RULES.structL_background_dk,0.006,220),
    accent:'#50A3F0',icon:oklchToHex(0.90,0,0),
    subtleFill:oklchToHex(RULES.structL_subtleFill_dk,0.006,220),
  }:{
    outline1:oklchToHex(RULES.structL_outline1,0,0),
    outline2:oklchToHex(RULES.structL_outline2,0,0),
    background:oklchToHex(RULES.structL_background,0,0),
    accent:'#0078D4',icon:'#242424',subtleFill:'#FFFFFF',
  };
  const neg=negativeHue(bH);
  const semantic=dark?{
    positive:oklchToHex(RULES.posL_dark,RULES.posC_dark,RULES.posH),
    negative:oklchToHex(neg.Ldark,neg.C,neg.H),
    neutral:oklchToHex(RULES.neuL_dark,RULES.neuC_dark,RULES.neuH),
  }:{
    positive:oklchToHex(RULES.posL_light,RULES.posC_light,RULES.posH),
    negative:oklchToHex(neg.Llight,neg.C,neg.H),
    neutral:oklchToHex(RULES.neuL_light,RULES.neuC_light,RULES.neuH),
  };
  const wallpaperH=(bH>=0&&bH<90)||(bH>=310)?30:220;
  const canvasBg=dark?oklchToHex(RULES.structL_canvasBg_dk,0.006,220):'#FFFFFF';
  const elBg=dark?oklchToHex(RULES.structL_elBg_dk,0.006,220):'#FFFFFF';
  const wallpaper=dark?oklchToHex(RULES.wallpaperL_dark,0.006,220):oklchToHex(RULES.wallpaperL_light,RULES.wallpaperC_light,wallpaperH);
  const borderCol=dark?oklchToHex(RULES.structL_outline2_dk,0.006,220):'#E0E0E0';
  const textCol=dark?'#E8E8E8':'#242424';
  const iconCol=dark?'#B0B0B0':'#616161';
  return{label:name,themeType:99,theme:{
    colors:{primaryColors:primaries,structuralColors:struct,semantic},
    page:{canvas:{background:{type:'color',color:canvasBg,imageUrl:''},
      border:{color:borderCol,side:'all',width:0,isEnabled:false},
      cornerRadius:{isCustomCornerRadius:false,isEnabled:true,radiusTopLeft:0,radiusTopRight:0,radiusBottomLeft:0,radiusBottomRight:0},
      shadow:{color:'#0000003f',blur:8,isEnabled:false,placement:'outer',side:'bottom',width:0,opacity:100,angle:135,distance:10},
      dimension:{dimensionType:'DEFAULT_16_9',width:1600,height:900},showGridLines:false,showVisualGuide:false},
      wallpaper:{type:'color',color:wallpaper,imageUrl:''}},
    elements:{background:{type:'color',color:elBg,imageUrl:''},
      border:{color:borderCol,side:'all',width:0,isEnabled:false},
      cornerRadius:{isCustomCornerRadius:false,isEnabled:true,radiusTopLeft:0,radiusTopRight:0,radiusBottomLeft:0,radiusBottomRight:0},
      shadow:{color:'#0000003f',blur:8,isEnabled:false,placement:'outer',side:'bottom',width:0,opacity:100,angle:135,distance:10},
      padding:{leftPadding:16,rightPadding:16,topPadding:16,bottomPadding:16,isCustomPaddingSize:false,isEnabled:true},
      header:{backgroundColor:elBg,borderColor:borderCol,iconColor:iconCol},
      tooltip:{backgroundColor:elBg,color:textCol}},
    typography:{autoFontColor:false,color:textCol,
      fontFamily:'"Segoe UI", wf_segoe-ui_normal, helvetica, arial, sans-serif',
      fontSize:14,responsiveFontSize:true}
  }};
}

/* ── Parse a pasted Coolors URL / hex list into an array of hex codes ──
   Accepts: full coolors.co URLs (hyphen-separated hex, no #),
   comma/space/newline separated hex lists, with or without '#'. ── */
function parseColorList(str){
  const matches=(str||'').match(/#?[0-9a-fA-F]{6}\b/g)||[];
  const seen=new Set(),out=[];
  matches.forEach(m=>{
    const n=norm(m);
    if(n&&!seen.has(n)){seen.add(n);out.push(n);}
  });
  return out.slice(0,8);
}

/* ── Build a full theme from a partial/complete palette (e.g. pasted from
   Coolors). If fewer than 8 colours are given, synthesize the remaining
   swatches by farthest-hue-point sampling in OKLCH space — each new hue is
   chosen to maximize its minimum perceptual distance to every hue already
   in the set (given + already-generated), so added colours read as a
   natural extension of the pasted palette rather than a jarring add-on. ── */
function generateThemeFromPalette(hexList,tone,name){
  const dark=tone==='dark';
  const existing=(hexList||[]).map(norm).filter(Boolean).slice(0,8);
  if(!existing.length)return null;
  let primaries=existing.slice();
  if(existing.length<8){
    const oklchs=existing.map(hexToOklch);
    const hues=oklchs.map(o=>o[2]);
    const avgL=oklchs.reduce((s,o)=>s+o[0],0)/oklchs.length;
    const avgC=oklchs.reduce((s,o)=>s+o[1],0)/oklchs.length;
    const achro=isAchromatic(avgC);
    const baseL=dark?clamp(avgL+RULES.chartL_dark_boost,CHART_L_MIN+0.08,CHART_L_MAX+0.10):clamp(avgL,CHART_L_MIN,CHART_L_MAX);
    const pC=achro?0.01:clamp(avgC,RULES.primC_min,RULES.primC_cap);
    const need=8-existing.length;
    for(let k=0;k<need;k++){
      let bestH=0,bestScore=-1;
      for(let cand=0;cand<360;cand+=2){
        let minD=999;
        for(const h of hues){const d=perceptualDist(cand,h);if(d<minD)minD=d;}
        if(minD>bestScore){bestScore=minD;bestH=cand;}
      }
      hues.push(bestH);
      const lOff=L_OFFSETS[(existing.length+k)%L_OFFSETS.length];
      const lo=achro?0.15:0.38,hi=achro?0.92:0.82;
      primaries.push(oklchToHex(clamp(baseL+lOff,lo,hi),pC,achro?0:bestH));
    }
  }
  const seedHue=hexToOklch(existing[0])[2];
  return themeFromPrimaries(primaries,tone,name,seedHue);
}

/* ══════════════════════════════════════════════════════════
   IMAGE PALETTE EXTRACTION — 100% client-side, no upload.
   Downscale → sample pixels → convert to OKLab (Cartesian, so plain
   Euclidean distance is perceptually meaningful and hue wrap-around
   isn't an issue) → k-means++ clustering → merge near-duplicate
   clusters → hand the resulting distinct hexes to
   generateThemeFromPalette() to fill out to 8 swatches if needed.
══════════════════════════════════════════════════════════ */
function rgbToOklab(r,g,b){
  const rl=_lin(r/255),gl=_lin(g/255),bl=_lin(b/255);
  const l=Math.cbrt(0.4122214708*rl+0.5363325363*gl+0.0514459929*bl);
  const m=Math.cbrt(0.2119034982*rl+0.6806995451*gl+0.1073969566*bl);
  const s=Math.cbrt(0.0883024619*rl+0.2817188376*gl+0.6299787005*bl);
  return[
    0.2104542553*l+0.7936177850*m-0.0040720468*s,
    1.9779984951*l-2.4285922050*m+0.4505937099*s,
    -0.0259040371*l+0.7827717662*m-0.8068517602*s
  ];
}
function oklabToHex(L,a,b){
  const C=Math.sqrt(a*a+b*b),H=(Math.atan2(b,a)*180/Math.PI+360)%360;
  return oklchToHex(L,C,H);
}

/* Downscale an <img>/<canvas>-able source onto an offscreen canvas and
   return {r,g,b} samples (strided, alpha-filtered). maxDim keeps the
   pixel count small so clustering stays fast even for large photos. */
function samplePixelsFromImage(img,maxDim=120,stride=3){
  const scale=Math.min(1,maxDim/Math.max(img.naturalWidth||img.width,img.naturalHeight||img.height));
  const w=Math.max(1,Math.round((img.naturalWidth||img.width)*scale));
  const h=Math.max(1,Math.round((img.naturalHeight||img.height)*scale));
  const cv=document.createElement('canvas');cv.width=w;cv.height=h;
  const ctx=cv.getContext('2d');
  ctx.drawImage(img,0,0,w,h);
  const data=ctx.getImageData(0,0,w,h).data;
  const samples=[];
  for(let i=0;i<data.length;i+=4*stride){
    if(data[i+3]<128)continue; // skip transparent pixels
    samples.push([data[i],data[i+1],data[i+2]]);
  }
  return samples;
}

/* k-means++ initialization: pick centroids that are spread apart rather
   than pure-random, so results are consistent run-to-run and converge
   in fewer iterations. */
function kmeansPlusPlusInit(points,k){
  const centroids=[points[Math.floor(Math.random()*points.length)]];
  while(centroids.length<k){
    const d2=points.map(p=>{
      let best=Infinity;
      for(const c of centroids){
        const dx=p[0]-c[0],dy=p[1]-c[1],dz=p[2]-c[2];
        const d=dx*dx+dy*dy+dz*dz;
        if(d<best)best=d;
      }
      return best;
    });
    const total=d2.reduce((a,b)=>a+b,0);
    if(total<=0){centroids.push(points[Math.floor(Math.random()*points.length)]);continue;}
    let r=Math.random()*total,idx=0;
    for(;idx<d2.length;idx++){r-=d2[idx];if(r<=0)break;}
    centroids.push(points[Math.min(idx,points.length-1)]);
  }
  return centroids;
}

/* Cluster OKLab points into k groups. Returns [{lab:[L,a,b], weight}]
   sorted by weight (most dominant colour first). */
function kmeansOklab(points,k,iterations=12){
  if(!points.length)return[];
  k=Math.min(k,points.length);
  let centroids=kmeansPlusPlusInit(points,k);
  let assign=new Array(points.length).fill(0);
  for(let iter=0;iter<iterations;iter++){
    let changed=false;
    for(let i=0;i<points.length;i++){
      let best=0,bestD=Infinity;
      for(let c=0;c<centroids.length;c++){
        const dx=points[i][0]-centroids[c][0],dy=points[i][1]-centroids[c][1],dz=points[i][2]-centroids[c][2];
        const d=dx*dx+dy*dy+dz*dz;
        if(d<bestD){bestD=d;best=c;}
      }
      if(assign[i]!==best){assign[i]=best;changed=true;}
    }
    const sums=centroids.map(()=>[0,0,0,0]);
    for(let i=0;i<points.length;i++){
      const s=sums[assign[i]];
      s[0]+=points[i][0];s[1]+=points[i][1];s[2]+=points[i][2];s[3]++;
    }
    centroids=sums.map((s,c)=>s[3]>0?[s[0]/s[3],s[1]/s[3],s[2]/s[3]]:centroids[c]);
    if(!changed)break;
  }
  const weights=new Array(centroids.length).fill(0);
  assign.forEach(a=>weights[a]++);
  return centroids
    .map((lab,i)=>({lab,weight:weights[i]}))
    .filter(c=>c.weight>0)
    .sort((a,b)=>b.weight-a.weight);
}

/* Extract up to `k` dominant hex colours from an <img> element.
   Merges clusters that are near-perceptual-duplicates (common when a
   photo doesn't actually contain 8 distinct colours) so the caller can
   see how many *truly* distinct colours were found and complete the
   rest via generateThemeFromPalette()'s existing fill-in logic. */
function extractPaletteFromImage(img,k=8){
  const samples=samplePixelsFromImage(img);
  if(!samples.length)return[];
  const labPoints=samples.map(([r,g,b])=>rgbToOklab(r,g,b));
  const clusters=kmeansOklab(labPoints,k);
  const merged=[];
  for(const c of clusters){
    const [L,a,b]=c.lab;
    const C=Math.sqrt(a*a+b*b),H=(Math.atan2(b,a)*180/Math.PI+360)%360;
    const dupe=merged.find(m=>Math.abs(m.L-L)<0.045&&perceptualDist(m.H,H)<9);
    if(dupe)continue;
    merged.push({L,H,hex:oklabToHex(L,a,b)});
  }
  return merged.map(m=>m.hex);
}

