/* Simple iterative Levenshtein (edit) distance — used only as a last
   resort when nothing matches directly, to catch typos/near-misses
   ("ocian" → "ocean"). No external library needed. */
function levenshtein(a,b){
  const m=a.length,n=b.length;
  if(!m)return n;if(!n)return m;
  let prev=Array.from({length:n+1},(_,j)=>j);
  for(let i=1;i<=m;i++){
    const cur=[i];
    for(let j=1;j<=n;j++){
      cur[j]=a[i-1]===b[j-1]?prev[j-1]:1+Math.min(prev[j-1],prev[j],cur[j-1]);
    }
    prev=cur;
  }
  return prev[n];
}

/* Deterministic string hash → used only for the final fallback, so
   different unmatched descriptions still land on different-but-
   consistent results instead of all collapsing to one identical grey
   theme. Not an attempt at understanding — just avoids flatness. */
function magicHash(s){
  let h=0;
  for(let i=0;i<s.length;i++)h=(h*31+s.charCodeAt(i))>>>0;
  return h;
}

function binLightness(L){return L<0.42?'dark':L>0.66?'bright':'balanced';}
function binSaturation(C){return C<0.07?'muted':C>0.13?'vivid':'balanced';}

/* Lazily-built merged lookup table combining MOOD_DICTIONARY, the
   synonym aliases, and the CSS colour corpus into one list of
   {term, hueRange, light, sat} entries all shaped the same way, so the
   matching loop in parseDescription() doesn't need to care which
   source a hit came from. */
let _magicKeysCache=null;
function magicAllKeys(){
  if(_magicKeysCache)return _magicKeysCache;
  const out=[];
  for(const term in MOOD_DICTIONARY)out.push({term,entry:MOOD_DICTIONARY[term]});
  for(const alias in MAGIC_ALIASES){
    const target=MOOD_DICTIONARY[MAGIC_ALIASES[alias]];
    if(target)out.push({term:alias,entry:target});
  }
  for(const name in CSS_COLOR_NAMES){
    if(name in MOOD_DICTIONARY)continue; // hand-tuned entry wins
    const[L,C,H]=hexToOklch(CSS_COLOR_NAMES[name]);
    out.push({term:name,entry:{hueRange:[H,H],light:binLightness(L),sat:binSaturation(C)}});
  }
  _magicKeysCache=out;
  return out;
}

/* Common filler words excluded from matching — without this, short
   words like "over" can be false-positive substring matches inside an
   unrelated dictionary term (e.g. "over" is literally inside
   "government"), which pollutes the blend with irrelevant hues. */
const MAGIC_STOPWORDS=new Set(['a','an','the','and','or','of','to','in','on','at','for','with','over','under','into','onto','from','by','is','this','that','my','our','your','it','its','be','as','about']);

/* Parse a free-text description into blended seed parameters. Runs a
   layered pipeline entirely offline:
     1. Substring match against MOOD_DICTIONARY + synonym aliases + the
        CSS colour-name corpus (all merged via magicAllKeys()), on both
        single tokens and bigrams ("night sky"). Filler words are
        stripped first (MAGIC_STOPWORDS) so short words can't falsely
        match merely by appearing inside an unrelated longer term.
     2. If that finds nothing, a fuzzy (edit-distance) pass catches
        typos/near-misses against the same merged key list — only the
        single closest match within a tight threshold is accepted, to
        avoid the same "coincidental short match" problem in a looser
        form.
     3. If still nothing, a deterministic hash of the input text picks
        a hue/lightness/saturation, so different unmatched phrases still
        land on different-but-consistent results instead of every miss
        collapsing to one identical grey theme.
   Multiple real matches are blended: hues are averaged circularly (so
   350° and 10° blend to 0°, not 180°), weighted by how specific
   (longer) the matched term was; lightness/saturation bias are picked
   by weighted majority vote. */
function parseDescription(text){
  const norm=(text||'').toLowerCase().trim();
  if(!norm)return{hue:220,light:'balanced',sat:'balanced',matched:[],usedFallback:true};
  const tokens=norm.split(/[^a-z]+/).filter(t=>t&&!MAGIC_STOPWORDS.has(t));
  const bigrams=[];
  for(let i=0;i<tokens.length-1;i++)bigrams.push(tokens[i]+' '+tokens[i+1]);
  const candidates=[...bigrams,...tokens];
  const allKeys=magicAllKeys();
  const matches=[];
  const seen=new Set();

  for(const cand of candidates){
    for(const{term,entry}of allKeys){
      if(seen.has(term))continue;
      // Substring containment alone isn't enough — a short term can
      // coincidentally appear inside an unrelated longer word (e.g.
      // the alias "ship" is literally inside "dealership"). Require
      // the shorter string to be at least half the length of the
      // longer one, so only genuinely close matches count.
      const shorter=Math.min(cand.length,term.length),longer=Math.max(cand.length,term.length);
      const substringHit=shorter>=3&&(cand.includes(term)||term.includes(cand))&&(shorter/longer)>=0.5;
      if(substringHit){
        matches.push({term,entry,specificity:term.length});
        seen.add(term);
      }
    }
  }

  /* Tier 2: fuzzy fallback — only if nothing matched directly. Only
     considers single tokens (bigrams are too noisy for edit-distance),
     and only accepts the single closest hit within a tight threshold,
     so a typo can be caught without opening the door to loose,
     coincidental matches. */
  if(!matches.length){
    let best=null,bestDist=Infinity;
    for(const tok of tokens){
      if(tok.length<4)continue;
      for(const{term,entry}of allKeys){
        if(Math.abs(term.length-tok.length)>2)continue;
        const d=levenshtein(tok,term);
        const threshold=tok.length<=5?1:2;
        if(d<=threshold&&d<bestDist){bestDist=d;best={term,entry};}
      }
    }
    if(best)matches.push({term:best.term,entry:best.entry,specificity:best.term.length});
  }

  if(!matches.length){
    const h=magicHash(norm);
    const lightOptions=['dark','balanced','bright'];
    const satOptions=['muted','balanced','vivid'];
    return{
      hue:h%360,
      light:lightOptions[(h>>>8)%3],
      sat:satOptions[(h>>>16)%3],
      matched:[],
      usedFallback:true
    };
  }

  const totalWeight=matches.reduce((s,m)=>s+m.specificity,0);
  let sinSum=0,cosSum=0;
  matches.forEach(m=>{
    const midHue=(m.entry.hueRange[0]+m.entry.hueRange[1])/2;
    const w=m.specificity/totalWeight;
    sinSum+=Math.sin(midHue*Math.PI/180)*w;
    cosSum+=Math.cos(midHue*Math.PI/180)*w;
  });
  const blendedHue=(Math.atan2(sinSum,cosSum)*180/Math.PI+360)%360;

  function pickBias(key,options){
    const scores={};
    options.forEach(o=>scores[o]=0);
    matches.forEach(m=>{scores[m.entry[key]]+=m.specificity;});
    return options.reduce((a,b)=>scores[a]>=scores[b]?a:b);
  }
  return{
    hue:blendedHue,
    light:pickBias('light',['dark','balanced','bright']),
    sat:pickBias('sat',['muted','balanced','vivid']),
    matched:matches.map(m=>m.term),
    usedFallback:false
  };
}

/* Convert blended seed params into a single seed hex colour via the
   existing OKLCH pipeline (same oklchToHex used everywhere else).
   Optional jitter nudges hue/lightness for "Try a variation" — the
   matched keywords stay the same, only the exact seed shifts a bit. */
function seedParamsToHex(params,jitter){
  const L_MAP={dark:0.32,balanced:0.52,bright:0.72};
  const C_MAP={muted:0.05,balanced:0.11,vivid:0.17};
  let L=L_MAP[params.light],C=C_MAP[params.sat],H=params.hue;
  if(jitter){
    H=(H+(jitter.hue||0)+360)%360;
    L=clamp(L+(jitter.light||0),0.18,0.85);
  }
  return oklchToHex(L,C,H);
}

/* Feed the seed straight into generateTheme() — the exact same
   OKLCH palette engine the Brand-colour flow uses. No separate colour
   logic; the only new part is the text→seed translation above. */
function generateMagicTheme(text,tone,name,jitter){
  const params=parseDescription(text);
  const seedHex=seedParamsToHex(params,jitter);
  return{theme:generateTheme(seedHex,tone,name),params,seedHex};
}

/* ── Optional online tier: ask Gemini for a seed colour + mood label ──
   Bring-your-own-key only (never hardcoded, never shipped in this file).
   Key lives in localStorage on the user's own browser. On any failure —
   missing key, network error, non-2xx (incl. 429 rate-limit), bad JSON,
   or timeout — the caller falls back to the deterministic engine above. */
const GEMINI_MODEL='gemini-2.0-flash';
function getGeminiKey(){
  try{return (localStorage.getItem('ntmGeminiKey')||'').trim();}catch(e){return '';}
}
async function callGeminiForSeed(text){
  const key=getGeminiKey();
  if(!key)throw new Error('no-key');
  const controller=new AbortController();
  const timeout=setTimeout(()=>controller.abort(),7000);
  try{
    const url=`https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent`;
    const prompt=`You pick a single representative colour for a UI theme based on a short description.\nDescription: "${text}"\nRespond with ONLY a compact JSON object, no markdown, no code fences, in this exact shape:\n{"hex":"#RRGGBB","mood":"one or two word mood label"}\nThe hex must be a colour that visually evokes the description (consider its typical real-world colours, mood, and industry connotations).`;
    const res=await fetch(url,{
      method:'POST',
      headers:{'Content-Type':'application/json','x-goog-api-key':key},
      body:JSON.stringify({contents:[{parts:[{text:prompt}]}]}),
      signal:controller.signal
    });
    if(!res.ok){
      if(res.status===429)throw new Error('rate-limited');
      throw new Error('http-'+res.status);
    }
    const data=await res.json();
    const raw=data?.candidates?.[0]?.content?.parts?.[0]?.text||'';
    const match=raw.match(/\{[^{}]*\}/);
    if(!match)throw new Error('bad-response');
    const parsed=JSON.parse(match[0]);
    const hex=norm(parsed.hex);
    if(!hex)throw new Error('bad-hex');
    return{hex,mood:(parsed.mood||'').toString().slice(0,40)};
  }finally{
    clearTimeout(timeout);
  }
}

