/* ── Tone ── */
document.querySelectorAll('.ntm-tone-btn').forEach(btn=>{
  btn.addEventListener('click',()=>{
    ntmTone=btn.dataset.tone;
    ntmToneManual=true;
    document.querySelectorAll('.ntm-tone-btn').forEach(b=>b.classList.remove('active'));
    btn.classList.add('active');
    document.getElementById('ntmToneDesc').textContent=ntmTone==='dark'?'Dark surfaces — near-black canvas, charcoal wallpaper, light text':'Light surfaces — white canvas, light wallpaper, dark text';
    // Tone governs surfaces (canvas/wallpaper/element bg/text) and semantic
    // lightness — clear any touched overrides on those specific slots so the
    // new tone actually takes effect (this matters most in Edit mode, where
    // every swatch starts out "touched" to preserve the existing theme).
    // Primary colours are untouched here — the chosen palette shouldn't
    // change just because the tone flipped.
    delete ntmTouched.canvas;delete ntmTouched.wallpaper;delete ntmTouched.elBg;delete ntmTouched.text;
    delete ntmTouched.posit;delete ntmTouched.negat;delete ntmTouched.neutr;
    scheduleGenerate(0);
  });
});

