/* ── Apply ── */
applyBtn.addEventListener('click',()=>{
  if(!ntmGenerated||applyBtn.disabled)return;
  const name=document.getElementById('ntmThemeName').value.trim()||'My Theme';
  ntmGenerated.label=name;
  T=JSON.parse(JSON.stringify(ntmGenerated));
  snapshotOrigin();buildAll();applyTheme();
  requestAnimationFrame(()=>requestAnimationFrame(fit));
  const nameLbl=document.getElementById('ftbThemeName');
  if(nameLbl)nameLbl.textContent=T.label;
  // Save to Library — update in-place if editing, prepend if new
  (function(){
    const lib=libLoad();
    const entry={...JSON.parse(JSON.stringify(T)),savedAt:Date.now()};
    if(ntmEditLibIdx!==null&&ntmEditLibIdx<lib.length){
      lib[ntmEditLibIdx]=entry; // update in-place
    } else {
      const existIdx=lib.findIndex(x=>x.label===T.label);
      if(existIdx>=0)lib[existIdx]=entry;else lib.unshift(entry);
    }
    libSave(lib);
  })();
  const wasEdit=ntmEditLibIdx!==null;
  modal.classList.remove('show');
  updateDeleteBtn();
  showToast(wasEdit?`"${T.label}" updated`:`"${T.label}" created and saved to Library`);
});

