/* ── Inline confirm/prompt (browser confirm/prompt blocked in iframes) ── */
function showConfirm(msg, onOk){
  const bg=document.getElementById('inlineDialogBg');
  const msgEl=document.getElementById('inlineDialogMsg');
  const inp=document.getElementById('inlineDialogInput');
  const okBtn=document.getElementById('inlineDialogOk');
  const cancelBtn=document.getElementById('inlineDialogCancel');
  msgEl.textContent=msg;
  inp.style.display='none';
  okBtn.textContent='Delete';
  okBtn.className='f-btn f-btn-danger-solid';
  cancelBtn.textContent='Cancel';
  bg.classList.add('show');
  const cleanup=()=>{bg.classList.remove('show');okBtn.onclick=null;cancelBtn.onclick=null;};
  okBtn.onclick=()=>{cleanup();onOk();};
  cancelBtn.onclick=()=>cleanup();
}

function showPrompt(msg, defaultVal, onOk){
  const bg=document.getElementById('inlineDialogBg');
  const msgEl=document.getElementById('inlineDialogMsg');
  const inp=document.getElementById('inlineDialogInput');
  const okBtn=document.getElementById('inlineDialogOk');
  const cancelBtn=document.getElementById('inlineDialogCancel');
  msgEl.textContent=msg;
  inp.style.display='block';
  inp.value=defaultVal||'';
  okBtn.textContent='Save';
  okBtn.className='f-btn f-btn-primary';
  cancelBtn.textContent='Cancel';
  bg.classList.add('show');
  setTimeout(()=>inp.focus(),50);
  const cleanup=()=>{bg.classList.remove('show');okBtn.onclick=null;cancelBtn.onclick=null;inp.onkeydown=null;};
  const confirm=()=>{const v=(inp.value||'').trim();if(!v)return;cleanup();onOk(v);};
  okBtn.onclick=confirm;
  inp.onkeydown=e=>{if(e.key==='Enter')confirm();if(e.key==='Escape')cleanup();};
  cancelBtn.onclick=()=>cleanup();
}

/* ── Toast notification ── */
function showToast(msg,duration=2800){
  let t=document.getElementById('_toast');
  if(!t){
    t=document.createElement('div');t.id='_toast';
    t.style.cssText='position:fixed;bottom:28px;left:50%;transform:translateX(-50%) translateY(20px);background:#242424;color:#fff;font-size:13px;font-family:var(--f-font);padding:10px 20px;border-radius:8px;box-shadow:0 4px 16px rgba(0,0,0,.3);z-index:9999;opacity:0;transition:opacity .2s,transform .2s;pointer-events:none;white-space:nowrap';
    document.body.appendChild(t);
  }
  t.textContent=msg;
  t.style.opacity='1';t.style.transform='translateX(-50%) translateY(0)';
  clearTimeout(t._timer);
  t._timer=setTimeout(()=>{t.style.opacity='0';t.style.transform='translateX(-50%) translateY(20px)';},duration);
}

