/* ══════════════════════════════════════════════════════════
   FEATURE: Shareable URL
   Encode theme as base64 in URL hash; decode on load.
══════════════════════════════════════════════════════════ */
function themeToHash(t){try{return '#t='+btoa(unescape(encodeURIComponent(JSON.stringify(t))));}catch(e){return '';}}
function hashToTheme(h){try{const b=h.replace('#t=','');return JSON.parse(decodeURIComponent(escape(atob(b))));}catch(e){return null;}}
// Load from hash on startup
(function(){
  if(location.hash&&location.hash.startsWith('#t=')){
    const obj=hashToTheme(location.hash);
    if(obj){T=obj;buildAll();applyTheme();requestAnimationFrame(fit);}
    history.replaceState(null,'',location.pathname);
  }
})();
$('#exportShareUrl').addEventListener('click',()=>{
  const url=location.href.split('#')[0]+themeToHash(T);
  navigator.clipboard&&navigator.clipboard.writeText(url);
  const b=$('#exportShareUrl'),t=b.textContent;
  b.textContent='URL copied ✓';b.classList.add('ok');
  setTimeout(()=>{b.textContent=t;b.classList.remove('ok');},1800);
});

/* ══════════════════════════════════════════════════════════
   FEATURE: Color blindness simulation
══════════════════════════════════════════════════════════ */
/* ── WCAG Validation ── */
(function(){
  const panel=document.getElementById('wcagPanel');
  const btn=document.getElementById('wcagBtn');
  const summary=document.getElementById('wcagSummary');
  const list=document.getElementById('wcagList');

  function wcagRun(){
    const c=T.theme.colors;
    const e=T.theme.elements;
    const p=T.theme.page;
    const typo=T.theme.typography;
    const canvasBg=p.canvas.background.color||'#FFFFFF';
    const elBg=e.background.color||'#FFFFFF';
    const textCol=typo.color||'#242424';
    const wallpaper=p.wallpaper.color||'#F5F5F5';

    // Every pair is checked against this theme's own actual
    // backgrounds (canvas/element/wallpaper) — never a hardcoded
    // white — so a dark theme's colours get judged against its real
    // dark backdrop instead of failing against a background it never
    // actually appears on.
    const pairs=[
      {name:'Text on Canvas',fg:textCol,bg:canvasBg,size:'normal'},
      {name:'Text on Element BG',fg:textCol,bg:elBg,size:'normal'},
      {name:'Text on Wallpaper',fg:textCol,bg:wallpaper,size:'normal'},
      ...c.primaryColors.map((col,i)=>({name:`Primary ${i+1} on Canvas`,fg:col,bg:canvasBg,size:'large'})),
      ...c.primaryColors.map((col,i)=>({name:`Primary ${i+1} on Element BG`,fg:col,bg:elBg,size:'large'})),
      {name:'Positive on Canvas',fg:c.semantic.positive,bg:canvasBg,size:'large'},
      {name:'Negative on Canvas',fg:c.semantic.negative,bg:canvasBg,size:'large'},
      {name:'Neutral on Canvas',fg:c.semantic.neutral,bg:canvasBg,size:'large'},
    ];

    let pass=0,fail=0;
    const rows=pairs.map(pair=>{
      const ratio=cr2(pair.fg,pair.bg);
      const threshold=pair.size==='normal'?4.5:3;
      const ok=ratio>=threshold;
      const largePassed=!ok&&ratio>=3&&pair.size==='normal';
      if(ok||(ratio>=3&&pair.size==='large'))pass++;else fail++;
      return{...pair,ratio,ok,largePassed};
    });

    // Summary
    summary.innerHTML=`
      <div class="wcag-stat pass-stat">
        <div class="wcag-stat-num">${pass}</div>
        <div class="wcag-stat-lbl">Pass</div>
      </div>
      <div class="wcag-stat fail-stat">
        <div class="wcag-stat-num">${fail}</div>
        <div class="wcag-stat-lbl">Fail</div>
      </div>`;

    // List — fails first, then passes
    const sorted=[...rows.filter(r=>!r.ok&&!r.largePassed),...rows.filter(r=>r.largePassed),...rows.filter(r=>r.ok)];
    list.innerHTML=sorted.map(r=>{
      const badge=r.ok?'pass':r.largePassed?'large':'fail';
      const badgeLbl=r.ok?'AA':(r.largePassed?'Large only':'Fail');
      return `<div class="wcag-item">
        <div class="wcag-item-swatch" style="background:${r.fg};outline:2px solid ${r.bg};outline-offset:-1px"></div>
        <div class="wcag-item-info">
          <div class="wcag-item-name">${r.name}</div>
          <div class="wcag-item-ratio">${r.ratio.toFixed(2)}:1 vs ${r.size==='normal'?'4.5':'3.0'}:1 threshold</div>
        </div>
        <span class="wcag-item-badge ${badge}">${badgeLbl}</span>
      </div>`;
    }).join('');
  }

  btn.addEventListener('click',()=>{
    if(panel.classList.contains('show')){panel.classList.remove('show');}
    else{wcagRun();panel.classList.add('show');}
  });
  document.getElementById('wcagClose').addEventListener('click',()=>panel.classList.remove('show'));

  // Re-run when theme changes
  window._wcagRefresh=()=>{if(panel.classList.contains('show'))wcagRun();};
})();

/* ── Color Vision Simulator ── */
const CBSIM_DATA={
  deuteranopia:{
    name:'Deuteranopia',
    prevalence:'~6% of males',
    desc:'The most common form of colour blindness. Caused by absent or non-functional M-cones (medium-wavelength / green receptors).',
    sees:'Reds and greens appear muted and difficult to distinguish. Both may shift toward yellow-brown. Blues and yellows remain relatively clear.'
  },
  protanopia:{
    name:'Protanopia',
    prevalence:'~2% of males',
    desc:'Caused by absent or non-functional L-cones (long-wavelength / red receptors). Less common than deuteranopia but more severe.',
    sees:'Reds appear very dark, almost black. Red-green confusion is stronger than deuteranopia. Bright reds may look black or very dark brown.'
  },
  tritanopia:{
    name:'Tritanopia',
    prevalence:'~0.01% of all people',
    desc:'A rare form caused by absent or non-functional S-cones (short-wavelength / blue receptors). Affects males and females equally.',
    sees:'Blues and greens are hard to distinguish. Yellows and pinks may appear red. Purples look like red. The world appears in red-green tones.'
  },
  achromatopsia:{
    name:'Achromatopsia',
    prevalence:'~0.003% of all people',
    desc:'Complete absence of colour vision (monochromacy). All cone types are non-functional. Extremely rare and usually accompanied by light sensitivity.',
    sees:'No colour at all — only shades of grey from light to dark. Everything appears as a greyscale photograph. Bright light is often painful.'
  }
};

let cbsimActive=false;
let cbsimType='deuteranopia';

function applyCbSim(type){
  const stage=document.getElementById('stage');
  stage.style.filter=type?'url(#cb-'+type+')':'';
}

function cbsimRenderInfo(type){
  const d=CBSIM_DATA[type];
  const el=document.getElementById('cbsimInfo');
  if(!el||!d)return;
  el.innerHTML=`
    <div class="cbsim-info-sees"><strong>What the user sees</strong>${d.sees}</div>`;
}

function cbsimSetMode(type){
  cbsimType=type;
  applyCbSim(type);
  cbsimRenderInfo(type);
  const sel=document.getElementById('cbsimSelect');
  if(sel)sel.value=type;
}

function cbsimShow(){
  const panel=document.getElementById('cbsimBar');
  panel.classList.add('show');
  cbsimSetMode(cbsimType);
  $('#cbsimBtn').classList.add('active');
  cbsimActive=true;
}

function cbsimHide(){
  const panel=document.getElementById('cbsimBar');
  panel.classList.remove('show');
  applyCbSim(null);
  $('#cbsimBtn').classList.remove('active');
  cbsimActive=false;
}

$('#cbsimBtn').addEventListener('click',()=>{cbsimActive?cbsimHide():cbsimShow();});
$('#cbsimOff').addEventListener('click',cbsimHide);
document.getElementById('cbsimSelect').addEventListener('change',function(){
  cbsimSetMode(this.value);
});

/* ── Draggable panel ── */
(function(){
  const panel=document.getElementById('cbsimBar');
  const header=panel.querySelector('.cbsim-header');
  let dragging=false,ox=0,oy=0;
  header.addEventListener('mousedown',e=>{
    if(e.target.closest('.cbsim-close'))return;
    dragging=true;
    const r=panel.getBoundingClientRect();
    // Switch from bottom/transform positioning to top/left so we can drag freely
    panel.style.bottom='auto';
    panel.style.transform='none';
    panel.style.left=r.left+'px';
    panel.style.top=r.top+'px';
    ox=e.clientX-r.left;
    oy=e.clientY-r.top;
    e.preventDefault();
  });
  document.addEventListener('mousemove',e=>{
    if(!dragging)return;
    let x=e.clientX-ox;
    let y=e.clientY-oy;
    // Clamp inside viewport
    x=Math.max(0,Math.min(window.innerWidth-panel.offsetWidth,x));
    y=Math.max(0,Math.min(window.innerHeight-panel.offsetHeight,y));
    panel.style.left=x+'px';
    panel.style.top=y+'px';
  });
  document.addEventListener('mouseup',()=>{dragging=false;});

  // If the panel has already been dragged to a free top/left position,
  // re-clamp it inside the viewport on resize (e.g. rotating a tablet,
  // or shrinking a browser window) so it can't get stranded off-screen.
  window.addEventListener('resize',()=>{
    if(panel.style.top==='' || panel.style.top==='auto')return;
    const x=Math.max(0,Math.min(window.innerWidth-panel.offsetWidth,parseFloat(panel.style.left)||0));
    const y=Math.max(0,Math.min(window.innerHeight-panel.offsetHeight,parseFloat(panel.style.top)||0));
    panel.style.left=x+'px';
    panel.style.top=y+'px';
  });
})();

